{
  "name": "Iboolimi Furniture Catalog",
  "description": "A high-end furniture catalog for the Uzbekistan market with a dual-role admin system and localized interface.",
  "requestFramePermissions": [
    "camera"
  ]
}

export enum Language {
  RU = 'ru',
  UZ = 'uz'
}

export enum UserRole {
  SUPER_ADMIN = 'SUPER_ADMIN',
  ADMIN = 'ADMIN'
}

export interface AdminUser {
  email: string;
  role: UserRole;
}

export interface Product {
  id: string;
  name: { [key in Language]: string };
  description: { [key in Language]: string };
  price: number;
  images: string[];
  category: string;
  dimensions: string;
  material: { [key in Language]: string };
  inStock: boolean;
}

export interface Order {
  id: string;
  productId: string;
  productName: string;
  customerName: string;
  customerPhone: string;
  customerEmail: string;
  timestamp: number;
}

export type AppState = {
  language: Language;
  products: Product[];
  admins: AdminUser[];
  currentUser: AdminUser | null;
};

import { GoogleGenAI, Type } from "@google/genai";

const API_KEY = process.env.API_KEY;

export const generateProductDescription = async (productName: string, language: 'ru' | 'uz') => {
  if (!API_KEY) return "AI service unavailable";

  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const prompt = `Write a professional, attractive sales description for a furniture item named "${productName}" in ${language === 'ru' ? 'Russian' : 'Uzbek'}. Keep it under 150 characters. Mention quality and comfort.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
    });
    return response.text?.trim() || "No description generated";
  } catch (error) {
    console.error("AI Generation Error:", error);
    return "Error generating description";
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Language, Product, AdminUser, UserRole } from './types';
import { SUPER_ADMIN_EMAIL, INITIAL_PRODUCTS, TRANSLATIONS } from './constants';
import Navbar from './components/Navbar';
import Catalog from './components/Catalog';
import ProductDetail from './components/ProductDetail';
import AdminPanel from './components/AdminPanel';
import LoginModal from './components/LoginModal';

const App: React.FC = () => {
  const [language, setLanguage] = useState<Language>(Language.RU);
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('iboolimi_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });
  const [admins, setAdmins] = useState<AdminUser[]>(() => {
    const saved = localStorage.getItem('iboolimi_admins');
    return saved ? JSON.parse(saved) : [{ email: SUPER_ADMIN_EMAIL, role: UserRole.SUPER_ADMIN }];
  });
  const [currentUser, setCurrentUser] = useState<AdminUser | null>(() => {
    const saved = sessionStorage.getItem('iboolimi_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [view, setView] = useState<{ type: 'catalog' | 'detail' | 'admin', productId?: string }>({ type: 'catalog' });
  const [showLogin, setShowLogin] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    localStorage.setItem('iboolimi_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('iboolimi_admins', JSON.stringify(admins));
  }, [admins]);

  const handleLogin = (email: string) => {
    const foundAdmin = admins.find(a => a.email.toLowerCase() === email.toLowerCase());
    if (foundAdmin) {
      setCurrentUser(foundAdmin);
      sessionStorage.setItem('iboolimi_session', JSON.stringify(foundAdmin));
      setShowLogin(false);
    } else {
      alert("Доступ запрещен / Ruxsat berilmagan");
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    sessionStorage.removeItem('iboolimi_session');
    setView({ type: 'catalog' });
  };

  const t = TRANSLATIONS[language];

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        language={language} 
        setLanguage={setLanguage}
        onAdminClick={() => currentUser ? setView({ type: 'admin' }) : setShowLogin(true)}
        onHomeClick={() => setView({ type: 'catalog' })}
        currentUser={currentUser}
        onLogout={handleLogout}
        t={t}
      />

      <main className="flex-grow">
        {view.type === 'catalog' && (
          <Catalog 
            products={products} 
            language={language} 
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            onProductClick={(id) => setView({ type: 'detail', productId: id })}
            t={t}
          />
        )}

        {view.type === 'detail' && view.productId && (
          <ProductDetail 
            product={products.find(p => p.id === view.productId)!}
            allProducts={products}
            language={language}
            onBack={() => setView({ type: 'catalog' })}
            onProductClick={(id) => setView({ type: 'detail', productId: id })}
            t={t}
          />
        )}

        {view.type === 'admin' && currentUser && (
          <AdminPanel 
            products={products}
            setProducts={setProducts}
            admins={admins}
            setAdmins={setAdmins}
            currentUser={currentUser}
            language={language}
            t={t}
          />
        )}
      </main>

      {showLogin && (
        <LoginModal 
          onLogin={handleLogin} 
          onClose={() => setShowLogin(false)} 
          t={t} 
        />
      )}

      <footer className="bg-gray-900 text-white py-12 px-4 mt-20">
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-3 gap-8 text-center md:text-left">
          <div>
            <h3 className="text-2xl font-bold mb-4">IBOOLIMI</h3>
            <p className="text-gray-400">Премиальная мебель для вашего дома в Узбекистане.</p>
          </div>
          <div>
            <h4 className="font-semibold mb-4">{t.categories}</h4>
            <ul className="text-gray-400 space-y-2">
              <li>{t.catalog}</li>
              <li>{t.uzbekistan}</li>
            </ul>
          </div>
          <div>
            <h4 className="font-semibold mb-4">Contact</h4>
            <p className="text-gray-400">iboolimi@gmail.com</p>
            <p className="text-gray-400">+998 90 000 00 00</p>
          </div>
        </div>
        <div className="mt-12 pt-8 border-t border-gray-800 text-center text-gray-500 text-sm">
          &copy; {new Date().getFullYear()} Iboolimi Furniture. All rights reserved.
        </div>
      </footer>
    </div>
  );
};

export default App;

