import React, { useState, useMemo } from 'react';
import { Product, Language } from '../types';
import { CATEGORIES } from '../constants';

interface CatalogProps {
  products: Product[];
  language: Language;
  searchQuery: string;
  setSearchQuery: (q: string) => void;
  onProductClick: (id: string) => void;
  t: any;
}

const Catalog: React.FC<CatalogProps> = ({ products, language, searchQuery, setSearchQuery, onProductClick, t }) => {
  const [activeCategory, setActiveCategory] = useState<string>('All');

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name[language].toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
      return matchesSearch && matchesCategory;
    });
  }, [products, searchQuery, activeCategory, language]);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Hero Section */}
      <div className="mb-12 relative overflow-hidden rounded-3xl bg-gray-900 h-[300px] md:h-[400px] flex items-center">
        <img 
          src="https://picsum.photos/seed/furniture-hero/1200/600" 
          alt="Hero" 
          className="absolute inset-0 w-full h-full object-cover opacity-50"
        />
        <div className="relative z-10 px-8 md:px-16 max-w-2xl">
          <h1 className="text-4xl md:text-6xl font-bold text-white mb-4 leading-tight">
            {language === Language.RU ? 'Комфорт и Стиль для вашего дома' : 'Uyingiz uchun qulaylik va uslub'}
          </h1>
          <p className="text-gray-300 text-lg md:text-xl">
            {language === Language.RU ? 'Выбирайте лучшее в Узбекистане' : "O'zbekistondagi eng yaxshi mebellarni tanlang"}
          </p>
        </div>
      </div>

      {/* Filters & Search */}
      <div className="flex flex-col md:flex-row gap-6 mb-12 items-start md:items-center justify-between">
        <div className="flex items-center space-x-2 overflow-x-auto pb-2 md:pb-0 w-full md:w-auto no-scrollbar">
          <button 
            onClick={() => setActiveCategory('All')}
            className={`px-5 py-2.5 rounded-full text-sm font-medium whitespace-nowrap transition ${activeCategory === 'All' ? 'bg-black text-white' : 'bg-white border border-gray-200 hover:bg-gray-50'}`}
          >
            {t.all}
          </button>
          {CATEGORIES.map(cat => (
            <button 
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`px-5 py-2.5 rounded-full text-sm font-medium whitespace-nowrap transition ${activeCategory === cat ? 'bg-black text-white' : 'bg-white border border-gray-200 hover:bg-gray-50'}`}
            >
              {cat}
            </button>
          ))}
        </div>

        <div className="relative w-full md:w-80">
          <input 
            type="text" 
            placeholder={t.search}
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-4 py-2.5 rounded-full border border-gray-200 focus:outline-none focus:ring-2 focus:ring-black/5"
          />
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 absolute left-3.5 top-3 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
          </svg>
        </div>
      </div>

      {/* Grid */}
      {filteredProducts.length > 0 ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
          {filteredProducts.map(product => (
            <div 
              key={product.id} 
              className="group cursor-pointer"
              onClick={() => onProductClick(product.id)}
            >
              <div className="relative aspect-[4/5] rounded-2xl overflow-hidden mb-4 bg-gray-100">
                <img 
                  src={product.images[0]} 
                  alt={product.name[language]}
                  className="w-full h-full object-cover group-hover:scale-105 transition duration-500"
                />
                {!product.inStock && (
                  <div className="absolute top-4 left-4 bg-red-500 text-white text-[10px] uppercase tracking-widest px-2 py-1 rounded font-bold">
                    Out of Stock
                  </div>
                )}
              </div>
              <div className="space-y-1">
                <div className="text-xs text-gray-400 uppercase tracking-widest">{product.category}</div>
                <h3 className="text-lg font-semibold group-hover:text-gray-600 transition">{product.name[language]}</h3>
                <div className="text-black font-bold text-lg">
                  {product.price.toLocaleString()} {t.currency}
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="text-center py-20 text-gray-400">
          <p className="text-xl">{t.noProducts}</p>
        </div>
      )}
    </div>
  );
};

export default Catalog;

import React, { useState } from 'react';
import { Product, Language } from '../types';

interface ProductDetailProps {
