    .filter(p => p.id !== product.id && p.category === product.category)
    .slice(0, 4);

  const handleOrder = (e: React.FormEvent) => {
    e.preventDefault();
    setIsOrdering(true);

    // Simulate API call to email iboolimi@gmail.com
    setTimeout(() => {
      console.log(`Order sent to iboolimi@gmail.com: 
        Product: ${product.name[language]}
        Customer: ${orderForm.name}
        Phone: ${orderForm.phone}
        Email: ${orderForm.email}
