      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 mb-20">
        {/* Gallery */}
        <div className="space-y-4">
          <div className="aspect-square rounded-3xl overflow-hidden bg-gray-100">
            <img 
              src={product.images[activeImage]} 
              alt={product.name[language]}
              className="w-full h-full object-cover transition duration-500"
            />
          </div>
          <div className="grid grid-cols-4 gap-4">
            {product.images.map((img, idx) => (
              <button 
                key={idx}
                onClick={() => setActiveImage(idx)}
                className={`aspect-square rounded-xl overflow-hidden border-2 transition ${activeImage === idx ? 'border-black' : 'border-transparent opacity-60 hover:opacity-100'}`}
