            <div className="text-2xl font-bold text-black">{product.price.toLocaleString()} {t.currency}</div>
          </div>

          <p className="text-gray-600 leading-relaxed text-lg">
            {product.description[language]}
          </p>

          <div className="border-y border-gray-100 py-6 space-y-4">
            <div className="flex justify-between items-center text-sm">
              <span className="text-gray-400 font-medium uppercase tracking-tighter">{t.dimensions}</span>
              <span className="font-semibold">{product.dimensions}</span>
            </div>
            <div className="flex justify-between items-center text-sm">
              <span className="text-gray-400 font-medium uppercase tracking-tighter">{t.material}</span>
              <span className="font-semibold">{product.material[language]}</span>
            </div>
