      {/* Related */}
      {related.length > 0 && (
        <div className="pt-20 border-t border-gray-100">
          <h2 className="text-2xl font-bold mb-8">{t.relatedProducts}</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
            {related.map(p => (
              <div 
                key={p.id} 
                className="group cursor-pointer"
                onClick={() => onProductClick(p.id)}
              >
                <div className="aspect-[4/5] rounded-2xl overflow-hidden mb-4 bg-gray-100">
                  <img 
                    src={p.images[0]} 
                    alt={p.name[language]}
                    className="w-full h-full object-cover group-hover:scale-105 transition"
                  />
                </div>
                <h3 className="font-semibold text-lg">{p.name[language]}</h3>
                <div className="text-gray-500 font-medium">{p.price.toLocaleString()} {t.currency}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default ProductDetail;

import React, { useState } from 'react';
import { Product, AdminUser, UserRole, Language } from '../types';
import { CATEGORIES } from '../constants';
import { generateProductDescription } from '../services/geminiService';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  admins: AdminUser[];
  setAdmins: React.Dispatch<React.SetStateAction<AdminUser[]>>;
  currentUser: AdminUser;
  language: Language;
  t: any;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  products, setProducts, admins, setAdmins, currentUser, language, t 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'team'>('products');
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);
  const [newAdminEmail, setNewAdminEmail] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const isSuperAdmin = currentUser.role === UserRole.SUPER_ADMIN;

  const saveProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;

    if (editingProduct.id) {
      setProducts(prev => prev.map(p => p.id === editingProduct.id ? (editingProduct as Product) : p));
    } else {
      const newProd: Product = {
        ...(editingProduct as Omit<Product, 'id'>),
        id: Date.now().toString(),
      };
      setProducts(prev => [newProd, ...prev]);
    }
    setEditingProduct(null);
  };

  const deleteProduct = (id: string) => {
    if (window.confirm('Delete product?')) {
      setProducts(prev => prev.filter(p => p.id !== id));
    }
  };

  const addAdmin = () => {
    if (!newAdminEmail || admins.find(a => a.email === newAdminEmail)) return;
    setAdmins(prev => [...prev, { email: newAdminEmail, role: UserRole.ADMIN }]);
    setNewAdminEmail('');
  };

  const removeAdmin = (email: string) => {
    if (email === currentUser.email) return;
    setAdmins(prev => prev.filter(a => a.email !== email));
  };

  const handleGenerateAI = async (lang: Language) => {
    const name = editingProduct?.name?.[lang];
    if (!name) return;

    setIsGenerating(true);
    const desc = await generateProductDescription(name, lang);
    setEditingProduct(prev => ({
      ...prev,
      description: {
        ...prev?.description,
        [lang]: desc
      }
    } as any));
    setIsGenerating(false);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-12">
        <h1 className="text-3xl font-bold">{t.adminPanel}</h1>
