          {isSuperAdmin && (
            <button 
              onClick={() => setActiveTab('team')}
              className={`px-6 py-2 rounded-lg text-sm font-semibold transition ${activeTab === 'team' ? 'bg-white shadow text-black' : 'text-gray-500'}`}
            >
              {t.team}
            </button>
          )}
        </div>
      </div>

      {activeTab === 'products' && (
        <div className="space-y-8">
          <div className="flex justify-end">
            <button 
              onClick={() => setEditingProduct({
                name: { [Language.RU]: '', [Language.UZ]: '' },
                description: { [Language.RU]: '', [Language.UZ]: '' },
                price: 0,
                images: ["https://picsum.photos/seed/new1/800/600", "https://picsum.photos/seed/new2/800/600", "https://picsum.photos/seed/new3/800/600"],
                category: CATEGORIES[0],
                dimensions: '',
                material: { [Language.RU]: '', [Language.UZ]: '' },
                inStock: true
              })}
              className="bg-black text-white px-6 py-2.5 rounded-xl font-bold hover:bg-gray-800 transition"
            >
              + {t.addProduct}
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {products.map(p => (
              <div key={p.id} className="bg-white border border-gray-100 p-4 rounded-2xl flex items-center space-x-4">
                <img src={p.images[0]} className="w-16 h-16 rounded-lg object-cover" />
                <div className="flex-grow min-w-0">
