import React, { useState } from 'react';
import { Product, AdminUser, UserRole, Language, MaterialType } from '../types';
import { CATEGORIES, SUPER_ADMIN_EMAIL } from '../constants';
import { generateProductDescription } from '../services/geminiService';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  admins: AdminUser[];
  setAdmins: React.Dispatch<React.SetStateAction<AdminUser[]>>;
  currentUser: AdminUser;
  language: Language;
  t: any;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  products, setProducts, admins, setAdmins, currentUser, language, t 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'team'>('products');
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);
  const [newAdminEmail, setNewAdminEmail] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const isSuperAdmin = currentUser.role === UserRole.SUPER_ADMIN;

  const saveProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;

    if (editingProduct.id) {
      setProducts(prev => prev.map(p => p.id === editingProduct.id ? (editingProduct as Product) : p));
    } else {
      const newProd: Product = {
        ...(editingProduct as Omit<Product, 'id'>),
        id: Date.now().toString(),
      };
      setProducts(prev => [newProd, ...prev]);
    }
    setEditingProduct(null);
  };

  const deleteProduct = (id: string) => {
    if (window.confirm('Delete product?')) {
      setProducts(prev => prev.filter(p => p.id !== id));
    }
  };

  const handleGenerateAI = async (lang: Language) => {
    const name = editingProduct?.name?.[lang];
    if (!name) return;

    setIsGenerating(true);
    const desc = await generateProductDescription(name, lang);
    setEditingProduct(prev => ({
      ...prev,
      description: { ...prev?.description, [lang]: desc }
    } as any));
    setIsGenerating(false);
  };

  const handleImagesChange = (val: string) => {
    const urls = val.split(',').map(u => u.trim()).filter(u => u.length > 0);
    setEditingProduct(prev => ({ ...prev, images: urls }));
  };

  return (
    <div className="max-w-7xl mx-auto px-6 py-12">
      <div className="flex justify-between items-center mb-16 border-b border-[#E5E5E0] pb-8">
        <h1 className="text-3xl font-light tracking-tight">{t.adminPanel}</h1>
        <div className="flex space-x-8">
          <button 
            onClick={() => setActiveTab('products')}
            className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 transition-all ${activeTab === 'products' ? 'border-black' : 'border-transparent text-gray-300'}`}
          >
            {t.catalog}
          </button>
          {isSuperAdmin && (
            <button 
              onClick={() => setActiveTab('team')}
              className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 transition-all ${activeTab === 'team' ? 'border-black' : 'border-transparent text-gray-300'}`}
            >
              {t.team}
            </button>
          )}
        </div>
      </div>

      {activeTab === 'products' && (
        <div className="space-y-12">
          <div className="flex justify-end">
            <button 
              onClick={() => setEditingProduct({
                name: { [Language.RU]: '', [Language.UZ]: '' },
                description: { [Language.RU]: '', [Language.UZ]: '' },
                price: 0,
                images: ["https://images.unsplash.com/photo-1540932239986-30128078f3c5?q=80&w=800"],
                category: CATEGORIES[0],
                materialType: 'Teak',
                dimensions: '',
                materialDetail: { [Language.RU]: '', [Language.UZ]: '' },
                inStock: true
              })}
              className="bg-black text-white px-8 py-3 text-[10px] font-bold tracking-widest uppercase hover:bg-gray-800 transition-colors"
            >
              + {t.addProduct}
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {products.map(p => (
              <div key={p.id} className="bg-white border border-[#E5E5E0] p-6 group hover:border-black transition-colors relative">
                <div className="aspect-square bg-[#F0F0EB] mb-4 overflow-hidden">
                  <img src={p.images[0]} className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500" />
                </div>
                <h4 className="font-medium text-sm mb-2">{p.name[language]}</h4>
                <div className="flex justify-between items-center">
                  <span className="text-xs text-gray-400">{p.price.toLocaleString()}</span>
                  <div className="flex space-x-2">
                    <button onClick={() => setEditingProduct(p)} className="p-2 text-gray-400 hover:text-black transition-colors">
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                    </button>
                    <button onClick={() => deleteProduct(p.id)} className="p-2 text-gray-400 hover:text-red-500 transition-colors">
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'team' && isSuperAdmin && (
        <div className="max-w-2xl bg-[#F9F9F7] p-12 border border-[#E5E5E0] mx-auto">
          <div className="flex space-x-4 mb-12">
            <input 
              type="email" placeholder="admin@gmail.com"
              value={newAdminEmail} onChange={e => setNewAdminEmail(e.target.value)}
              className="flex-grow bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors"
            />
            <button 
              onClick={() => {
                if (newAdminEmail) setAdmins([...admins, { email: newAdminEmail, role: UserRole.ADMIN }]);
                setNewAdminEmail('');
              }}
              className="bg-black text-white px-8 py-3 text-[10px] font-bold tracking-widest uppercase"
            >
              Add
            </button>
          </div>
          <div className="space-y-4">
            {admins.map(admin => (
              <div key={admin.email} className="flex justify-between items-center py-4 border-b border-[#E5E5E0] last:border-0">
                <div className="text-sm font-medium">{admin.email}</div>
                <div className="text-[10px] uppercase tracking-widest font-bold text-gray-300">{admin.role}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Product Modal */}
      {editingProduct && (
        <div className="fixed inset-0 z-[60] bg-[#F9F9F7]/95 backdrop-blur overflow-y-auto">
          <div className="max-w-4xl mx-auto py-20 px-6">
            <h2 className="text-3xl font-light tracking-tight mb-12">{editingProduct.id ? t.editProduct : t.addProduct}</h2>
            <form onSubmit={saveProduct} className="grid grid-cols-1 md:grid-cols-2 gap-16">
              <div className="space-y-8">
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Name (RU)</label>
                  <input 
                    required value={editingProduct.name?.[Language.RU]} 
                    onChange={e => setEditingProduct({...editingProduct, name: {...editingProduct.name!, [Language.RU]: e.target.value}} as any)}
                    className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors"
                  />
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Material Type</label>
                  <select 
                    value={editingProduct.materialType}
                    onChange={e => setEditingProduct({...editingProduct, materialType: e.target.value as MaterialType})}
                    className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none"
                  >
                    <option value="Teak">Teak</option>
                    <option value="Rattan">Rattan</option>
                    <option value="Bamboo">Bamboo</option>
                    <option value="Stone">Stone</option>
                    <option value="Textile">Textile</option>
                  </select>
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">{t.imageUrls}</label>
                  <textarea 
                    placeholder="https://image1.jpg, https://image2.jpg"
                    value={editingProduct.images?.join(', ')}
                    onChange={e => handleImagesChange(e.target.value)}
                    className="w-full bg-[#F0F0EB] p-4 text-xs focus:outline-none focus:ring-1 focus:ring-black"
                    rows={3}
                  />
                </div>
                <div>
                  <div className="flex justify-between mb-2">
                    <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400">Description (RU)</label>
                    <button type="button" onClick={() => handleGenerateAI(Language.RU)} className="text-[10px] font-bold text-[#8E9775]">{isGenerating ? '...' : t.aiGenerate}</button>
                  </div>
                  <textarea 
                    value={editingProduct.description?.[Language.RU]}
                    onChange={e => setEditingProduct({...editingProduct, description: {...editingProduct.description!, [Language.RU]: e.target.value}} as any)}
                    className="w-full bg-[#F0F0EB] p-4 text-sm focus:outline-none" rows={4}
                  />
                </div>
              </div>
              <div className="space-y-8">
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Price</label>
                  <input 
                    type="number" value={editingProduct.price}
                    onChange={e => setEditingProduct({...editingProduct, price: Number(e.target.value)})}
                    className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors"
                  />
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Dimensions</label>
                  <input 
                    value={editingProduct.dimensions}
                    onChange={e => setEditingProduct({...editingProduct, dimensions: e.target.value})}
                    placeholder="200x100x75 cm"
                    className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors"
                  />
                </div>
                <div className="flex space-x-4 pt-12">
                  <button type="submit" className="flex-grow bg-black text-white py-5 text-[10px] font-bold tracking-widest uppercase">Save</button>
                  <button type="button" onClick={() => setEditingProduct(null)} className="px-10 border border-[#E5E5E0] py-5 text-[10px] font-bold tracking-widest uppercase">Close</button>
