export default AdminPanel;

import React, { useState, useMemo } from 'react';
import { Product, Language } from '../types';
import { CATEGORIES, CATEGORY_COVERS } from '../constants';

interface CatalogProps {
  products: Product[];
  language: Language;
  searchQuery: string;
  setSearchQuery: (q: string) => void;
  onProductClick: (id: string) => void;
  t: any;
}

const Catalog: React.FC<CatalogProps> = ({ products, language, searchQuery, setSearchQuery, onProductClick, t }) => {
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [hoveredCat, setHoveredCat] = useState<string | null>(null);

  const filteredProducts = useMemo(() => {
    if (!selectedCategory) return [];
    return products.filter(p => {
      const matchesSearch = p.name[language].toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'All' || p.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [products, searchQuery, selectedCategory, language]);

  // If no category selected, show "Divisions"
  if (!selectedCategory && !searchQuery) {
    return (
      <div className="max-w-7xl mx-auto px-6 py-20 animate-in fade-in duration-1000">
        <div className="mb-24 text-center space-y-6">
          <h1 className="text-5xl md:text-7xl font-extralight tracking-tighter text-black">
            {t.brandName}
          </h1>
          <p className="text-gray-400 tracking-[0.3em] uppercase text-xs font-medium">
            {t.tagline}
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {CATEGORIES.map(cat => (
            <div 
              key={cat}
              className="group relative aspect-[4/5] overflow-hidden cursor-pointer bg-[#F0F0EB]"
              onClick={() => setSelectedCategory(cat)}
              onMouseEnter={() => setHoveredCat(cat)}
              onMouseLeave={() => setHoveredCat(null)}
            >
              <img 
                src={CATEGORY_COVERS[cat]} 
                alt={cat}
                className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110 grayscale-[0.2] group-hover:grayscale-0"
              />
              <div className="absolute inset-0 bg-black/10 group-hover:bg-black/30 transition-colors duration-500" />
              <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">
                <h3 className="text-white text-2xl font-light tracking-widest uppercase mb-4 translate-y-4 group-hover:translate-y-0 transition-transform duration-500">
                  {t.categoryTitles[cat] || cat}
                </h3>
                <div className="w-12 h-[1px] bg-white/50 group-hover:w-24 transition-all duration-500 mb-6" />
                <button className="text-[10px] text-white font-bold tracking-[0.3em] uppercase opacity-0 group-hover:opacity-100 transition-opacity duration-500">
                  {t.viewCategory}
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-6 py-12 animate-in fade-in duration-500">
      {/* Header for Category View */}
      <div className="flex flex-col md:flex-row gap-8 mb-16 items-center justify-between">
        <div className="flex items-center space-x-6">
          <button 
            onClick={() => setSelectedCategory(null)}
            className="p-3 rounded-full border border-[#E5E5E0] hover:bg-black hover:text-white transition-all"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
          </button>
          <h2 className="text-3xl font-light tracking-tight">
            {selectedCategory === 'All' ? t.all : (t.categoryTitles[selectedCategory!] || selectedCategory)}
          </h2>
        </div>

        <div className="relative w-full md:w-64">
          <input 
            type="text" 
            placeholder={t.search}
            value={searchQuery}
            onChange={(e) => {
              setSearchQuery(e.target.value);
              if (!selectedCategory) setSelectedCategory('All');
            }}
            className="w-full bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none focus:border-black transition-colors"
          />
        </div>
      </div>

      {/* Grid of Products in Category */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-x-12 gap-y-20">
        {(searchQuery && !selectedCategory ? products.filter(p => p.name[language].toLowerCase().includes(searchQuery.toLowerCase())) : filteredProducts).map(product => (
          <div 
            key={product.id} 
            className="group cursor-pointer"
            onClick={() => onProductClick(product.id)}
          >
            <div className="relative aspect-[3/4] overflow-hidden bg-[#F0F0EB] mb-6">
              <img 
                src={product.images[0]} 
                alt={product.name[language]}
                className="w-full h-full object-cover grayscale-[0.3] group-hover:grayscale-0 group-hover:scale-105 transition-all duration-700"
              />
              <div className="absolute bottom-6 left-6 right-6">
                <button className="w-full bg-white/90 backdrop-blur py-3 text-[10px] font-bold tracking-widest uppercase opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-2 group-hover:translate-y-0">
                  {t.quickView}
                </button>
              </div>
            </div>
            <div className="space-y-2">
              <div className="flex justify-between items-start">
                <div>
                  <h3 className="text-lg font-light tracking-tight">{product.name[language]}</h3>
                  <p className="text-[10px] text-gray-400 uppercase tracking-widest">{product.materialType}</p>
                </div>
                <div className="text-sm font-medium">
                  {product.price.toLocaleString()} {t.currency}
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {(selectedCategory && filteredProducts.length === 0) && (
        <div className="py-40 text-center">
          <p className="text-gray-300 tracking-[0.2em] italic">{t.noProducts}</p>
        </div>
      )}
    </div>
  );
};

