          <div className="grid grid-cols-4 gap-4">
            {product.images.map((img, idx) => (
              <button 
                key={idx}
                onClick={() => setActiveImage(idx)}
                className={`aspect-square overflow-hidden border transition-colors ${activeImage === idx ? 'border-black' : 'border-transparent opacity-60'}`}
              >
                <img src={img} className="w-full h-full object-cover" />
              </button>
            ))}
          </div>
        </div>

        {/* Info */}
        <div className="lg:col-span-5 space-y-12">
          <div className="space-y-4">
            <h1 className="text-4xl md:text-5xl font-light tracking-tight">{product.name[language]}</h1>
            <p className="text-gray-400 text-sm leading-relaxed max-w-md">
              {product.description[language]}
            </p>
            <div className="text-2xl font-medium pt-4">
              {product.price > 0 ? product.price.toLocaleString() : ''} {product.price > 0 ? t.currency : ''}
            </div>
          </div>

          <div className="space-y-6 pt-12 border-t border-[#E5E5E0]">
            <div className="flex justify-between items-center py-2">
              <span className="text-[10px] font-bold tracking-widest uppercase text-gray-400">{t.dimensions}</span>
              <span className="text-sm">{product.dimensions}</span>
            </div>
            <div className="flex justify-between items-center py-2">
              <span className="text-[10px] font-bold tracking-widest uppercase text-gray-400">{t.material}</span>
              <span className="text-sm">{product.materialDetail[language]}</span>
            </div>
          </div>

          {!orderSuccess ? (
            <form onSubmit={handleOrder} className="bg-[#F9F9F7] p-8 space-y-6 mt-12">
              <h3 className="text-sm font-bold tracking-widest uppercase mb-4">{t.order}</h3>
              <input 
                required placeholder={t.name}
                value={orderForm.name} onChange={e => setOrderForm({...orderForm, name: e.target.value})}
                className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors"
              />
              <input 
                required placeholder={t.phone}
                value={orderForm.phone} onChange={e => setOrderForm({...orderForm, phone: e.target.value})}
                className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors"
              />
              <input 
                required type="email" placeholder={t.email}
                value={orderForm.email} onChange={e => setOrderForm({...orderForm, email: e.target.value})}
                className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors"
              />
              <button 
                type="submit" disabled={isOrdering}
                className="w-full bg-black text-white py-5 text-[10px] font-bold tracking-[0.3em] uppercase hover:bg-gray-800 transition-colors disabled:opacity-50"
              >
                {isOrdering ? '...' : t.submitOrder}
              </button>
            </form>
          ) : (
            <div className="bg-[#F1F5E8] p-12 text-center space-y-6 animate-in slide-in-from-top-4">
              <div className="w-12 h-12 bg-[#8E9775] text-white rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
              </div>
              <p className="text-sm font-medium tracking-wide">{t.orderSuccess}</p>
              <p className="text-[10px] uppercase tracking-widest text-[#8E9775]">{t.orderEmailNotice}</p>
            </div>
          )}
        </div>
      </div>

      {/* Similar Products Block */}
      {similarProducts.length > 0 && (
        <div className="pt-24 border-t border-[#E5E5E0]">
          <h2 className="text-xs font-bold tracking-[0.3em] uppercase mb-12 text-gray-400">{t.relatedProducts}</h2>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-12">
            {similarProducts.map(p => (
              <div 
                key={p.id} 
                className="group cursor-pointer space-y-4"
                onClick={() => onProductClick(p.id)}
              >
                <div className="aspect-[4/5] bg-[#F0F0EB] overflow-hidden">
                  <img 
                    src={p.images[0]} 
                    alt={p.name[language]}
                    className="w-full h-full object-cover grayscale-[0.3] group-hover:grayscale-0 group-hover:scale-105 transition-all duration-700"
                  />
                </div>
                <div className="flex justify-between items-center">
                  <h4 className="text-sm font-light">{p.name[language]}</h4>
                  <span className="text-[10px] font-medium text-gray-500">{p.price > 0 ? p.price.toLocaleString() : ''} {p.price > 0 ? t.currency : ''}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

