{
  "name": "Iboolimi Furniture Catalog",
  "description": "A high-end furniture catalog for the Uzbekistan market with a dual-role admin system and localized interface.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React, { useState, useRef, useEffect } from 'react';
import { Product, AdminUser, UserRole, Language, MaterialType } from '../types';
import { CATEGORIES, TRANSLATIONS } from '../constants';
import { generateProductDescription } from '../services/geminiService';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  admins: AdminUser[];
  setAdmins: React.Dispatch<React.SetStateAction<AdminUser[]>>;
  currentUser: AdminUser;
  language: Language;
  t: any;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  products, setProducts, admins, setAdmins, currentUser, language, t 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'team'>('products');
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);
  const [newAdminEmail, setNewAdminEmail] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const isSuperAdmin = currentUser.role === UserRole.SUPER_ADMIN;

  const saveProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;

    if (editingProduct.id) {
      setProducts(prev => prev.map(p => p.id === editingProduct.id ? (editingProduct as Product) : p));
    } else {
      const newProd: Product = {
        ...(editingProduct as Omit<Product, 'id'>),
        id: Date.now().toString(),
      };
      setProducts(prev => [newProd, ...prev]);
    }
    setEditingProduct(null);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    const loaders = Array.from(files).map(file => {
      return new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
    });

    Promise.all(loaders).then(base64Images => {
      setEditingProduct(prev => ({
        ...prev,
        images: [...(prev?.images || []), ...base64Images]
      }));
    });
  };

  const removeImage = (index: number) => {
    setEditingProduct(prev => ({
      ...prev,
      images: (prev?.images || []).filter((_, i) => i !== index)
    }));
  };

  const openCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' } 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
      setIsCameraOpen(true);
    } catch (err) {
      console.error("Camera error:", err);
      alert("Не удалось получить доступ к камере.");
    }
  };

  const closeCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    setIsCameraOpen(false);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg');
        setEditingProduct(prev => ({
          ...prev,
          images: [...(prev?.images || []), dataUrl]
        }));
        closeCamera();
      }
    }
  };

  // Clean up stream on unmount
  useEffect(() => {
    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  return (
    <div className="max-w-7xl mx-auto px-6 py-12 animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-16 border-b border-[#E5E5E0] pb-8">
        <h1 className="text-3xl font-light tracking-tight">{t.adminPanel}</h1>
        <div className="flex space-x-8">
          <button 
            onClick={() => setActiveTab('products')}
            className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 transition-all ${activeTab === 'products' ? 'border-black' : 'border-transparent text-gray-300'}`}
          >
            {t.catalog}
          </button>
          {isSuperAdmin && (
            <button 
              onClick={() => setActiveTab('team')}
              className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 transition-all ${activeTab === 'team' ? 'border-black' : 'border-transparent text-gray-300'}`}
            >
              {t.team}
            </button>
          )}
        </div>
      </div>

      {activeTab === 'products' && (
        <div className="space-y-12">
          <div className="flex justify-end">
            <button 
              onClick={() => setEditingProduct({
                name: { [Language.RU]: '', [Language.UZ]: '' },
                description: { [Language.RU]: '', [Language.UZ]: '' },
                price: 0,
                images: [],
                category: CATEGORIES[0],
                materialType: 'Teak',
                dimensions: '',
                materialDetail: { [Language.RU]: '', [Language.UZ]: '' },
                inStock: true
              })}
              className="bg-black text-white px-8 py-3 text-[10px] font-bold tracking-widest uppercase hover:bg-gray-800 transition-colors"
            >
              + {t.addProduct}
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {products.map(p => (
              <div key={p.id} className="bg-white border border-[#E5E5E0] p-6 group hover:border-black transition-colors relative">
                <div className="aspect-square bg-[#F0F0EB] mb-4 overflow-hidden">
                  <img src={p.images[0]} className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500" />
                </div>
                <div className="mb-2">
                   <div className="text-[9px] text-gray-400 uppercase tracking-widest mb-1">{(TRANSLATIONS[language].categoryTitles as any)[p.category] || p.category}</div>
                   <h4 className="font-medium text-sm">{p.name[language]}</h4>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-xs text-gray-400">{p.price > 0 ? p.price.toLocaleString() : ''} {p.price > 0 ? t.currency : ''}</span>
                  <div className="flex space-x-2">
                    <button onClick={() => setEditingProduct(p)} className="p-2 text-gray-400 hover:text-black transition-colors">
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                    </button>
                    <button onClick={() => setProducts(products.filter(pr => pr.id !== p.id))} className="p-2 text-gray-400 hover:text-red-500 transition-colors">
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'team' && isSuperAdmin && (
        <div className="max-w-2xl bg-[#F9F9F7] p-12 border border-[#E5E5E0] mx-auto">
          <div className="flex space-x-4 mb-12">
            <input 
              type="email" placeholder="admin@gmail.com"
              value={newAdminEmail} onChange={e => setNewAdminEmail(e.target.value)}
              className="flex-grow bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors"
            />
            <button 
              onClick={() => {
                if (newAdminEmail) setAdmins([...admins, { email: newAdminEmail, role: UserRole.ADMIN }]);
                setNewAdminEmail('');
              }}
              className="bg-black text-white px-8 py-3 text-[10px] font-bold tracking-widest uppercase"
            >
              Add
            </button>
          </div>
          <div className="space-y-4">
            {admins.map(admin => (
              <div key={admin.email} className="flex justify-between items-center py-4 border-b border-[#E5E5E0] last:border-0">
                <div className="text-sm font-medium">{admin.email}</div>
                <div className="text-[10px] uppercase tracking-widest font-bold text-gray-300">{admin.role}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {editingProduct && (
        <div className="fixed inset-0 z-[60] bg-[#F9F9F7]/95 backdrop-blur overflow-y-auto">
          <div className="max-w-4xl mx-auto py-20 px-6">
            <h2 className="text-3xl font-light tracking-tight mb-12">{editingProduct.id ? t.editProduct : t.addProduct}</h2>
            <form onSubmit={saveProduct} className="grid grid-cols-1 md:grid-cols-2 gap-16">
              <div className="space-y-8">
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Название (RU)</label>
                  <input 
                    required value={editingProduct.name?.[Language.RU]} 
                    onChange={e => setEditingProduct({...editingProduct, name: {...editingProduct.name!, [Language.RU]: e.target.value}} as any)}
                    className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors"
                  />
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">{t.categories}</label>
                  <select 
                    value={editingProduct.category}
                    onChange={e => setEditingProduct({...editingProduct, category: e.target.value})}
                    className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none"
                  >
                    {CATEGORIES.map(cat => (
                      <option key={cat} value={cat}>{(TRANSLATIONS[Language.RU].categoryTitles as any)[cat] || cat}</option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-4">{t.imageUpload}</label>
                  <div className="grid grid-cols-3 gap-4 mb-4">
                    {editingProduct.images?.map((img, idx) => (
                      <div key={idx} className="relative aspect-square bg-gray-100 rounded-lg overflow-hidden group">
                        <img src={img} className="w-full h-full object-cover" />
                        <button 
                          type="button" 
                          onClick={() => removeImage(idx)}
                          className="absolute inset-0 flex items-center justify-center bg-black/40 text-white opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                      </div>
                    ))}
                    <div className="flex flex-col gap-2">
                      <label className="aspect-square border-2 border-dashed border-[#E5E5E0] rounded-lg flex items-center justify-center cursor-pointer hover:border-black transition-colors" title={t.imageUpload}>
                        <svg className="w-6 h-6 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                        <input type="file" multiple accept="image/*" className="hidden" onChange={handleImageUpload} />
                      </label>
                      <button 
                        type="button"
                        onClick={openCamera}
                        className="aspect-square border-2 border-dashed border-[#E5E5E0] rounded-lg flex items-center justify-center cursor-pointer hover:border-black transition-colors"
                        title={t.takePhoto}
                      >
                        <svg className="w-6 h-6 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
                        </svg>
                      </button>
                    </div>
                  </div>
                </div>
              </div>
              <div className="space-y-8">
                <div>
                  <div className="flex justify-between items-center mb-2">
                    <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400">Описание (RU)</label>
                    <button 
                      type="button" 
                      onClick={() => handleGenerateAI(Language.RU)}
                      disabled={isGenerating}
                      className="text-[10px] font-bold text-gray-400 hover:text-black transition-colors uppercase tracking-widest"
                    >
                      {isGenerating ? '...' : t.aiGenerate}
                    </button>
                  </div>
                  <textarea 
                    value={editingProduct.description?.[Language.RU]}
                    onChange={e => setEditingProduct({...editingProduct, description: {...editingProduct.description!, [Language.RU]: e.target.value}} as any)}
                    className="w-full bg-[#F0F0EB] p-4 text-sm focus:outline-none" rows={4}
                  />
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">{t.price}</label>
                  <input 
                    type="number" 
                    value={editingProduct.price || ''}
                    onChange={e => setEditingProduct({...editingProduct, price: Number(e.target.value)})}
                    className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors"
                  />
                </div>
                <div className="flex space-x-4 pt-12">
                  <button type="submit" className="flex-grow bg-black text-white py-5 text-[10px] font-bold tracking-widest uppercase">Save</button>
                  <button type="button" onClick={() => setEditingProduct(null)} className="px-10 border border-[#E5E5E0] py-5 text-[10px] font-bold tracking-widest uppercase">Close</button>
                </div>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Camera Modal */}
      {isCameraOpen && (
        <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-4">
          <div className="relative w-full max-w-2xl aspect-[4/3] bg-gray-900 rounded-2xl overflow-hidden shadow-2xl">
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className="w-full h-full object-cover"
            />
            <div className="absolute bottom-8 left-0 right-0 flex justify-center space-x-8">
              <button 
                onClick={closeCamera}
                className="bg-white/10 backdrop-blur-md text-white px-8 py-3 rounded-full text-xs font-bold tracking-widest uppercase hover:bg-white/20 transition-all border border-white/20"
              >
                {t.cancel}
              </button>
              <button 
                onClick={capturePhoto}
                className="bg-white text-black w-16 h-16 rounded-full flex items-center justify-center hover:scale-110 active:scale-95 transition-all shadow-xl"
              >
                <div className="w-12 h-12 rounded-full border-2 border-black" />
              </button>
            </div>
          </div>
          <canvas ref={canvasRef} className="hidden" />
        </div>
      )}
    </div>
  );
};

