  const removeImage = (index: number) => {
    setEditingProduct(prev => ({
      ...prev,
      images: (prev?.images || []).filter((_, i) => i !== index)
    }));
  };

  const openCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' } 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
      setIsCameraOpen(true);
    } catch (err) {
      console.error("Camera error:", err);
      alert("Не удалось получить доступ к камере.");
    }
  };

  const closeCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    setIsCameraOpen(false);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg');
        setEditingProduct(prev => ({
          ...prev,
          images: [...(prev?.images || []), dataUrl]
        }));
        closeCamera();
      }
    }
  };

  // Fix: Added missing handleGenerateAI function to process product description generation via Gemini API.
  const handleGenerateAI = async (lang: Language) => {
    const productName = editingProduct?.name?.[lang];
    if (!productName || isGenerating) return;

    setIsGenerating(true);
    try {
      const result = await generateProductDescription(productName, lang);
      setEditingProduct(prev => {
        if (!prev) return prev;
        return {
          ...prev,
          description: {
            ...(prev.description || {}),
            [lang]: result
          }
        } as Partial<Product>;
      });
    } catch (error) {
      console.error("AI Generation Error:", error);
    } finally {
      setIsGenerating(false);
    }
  };

  // Clean up stream on unmount
  useEffect(() => {
    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  return (
    <div className="max-w-7xl mx-auto px-6 py-12 animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-16 border-b border-[#E5E5E0] pb-8">
        <h1 className="text-3xl font-light tracking-tight">{t.adminPanel}</h1>
        <div className="flex space-x-8">
          <button 
            onClick={() => setActiveTab('products')}
            className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 transition-all ${activeTab === 'products' ? 'border-black' : 'border-transparent text-gray-300'}`}
          >
            {t.catalog}
          </button>
          {isSuperAdmin && (
            <button 
              onClick={() => setActiveTab('team')}
              className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 transition-all ${activeTab === 'team' ? 'border-black' : 'border-transparent text-gray-300'}`}
            >
              {t.team}
            </button>
          )}
        </div>
      </div>

      {activeTab === 'products' && (
        <div className="space-y-12">
          <div className="flex justify-end">
            <button 
              onClick={() => setEditingProduct({
                name: { [Language.RU]: '', [Language.UZ]: '' },
                description: { [Language.RU]: '', [Language.UZ]: '' },
                price: 0,
                images: [],
                category: CATEGORIES[0],
                materialType: 'Teak',
                dimensions: '',
                materialDetail: { [Language.RU]: '', [Language.UZ]: '' },
                inStock: true
              })}
              className="bg-black text-white px-8 py-3 text-[10px] font-bold tracking-widest uppercase hover:bg-gray-800 transition-colors"
            >
              + {t.addProduct}
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {products.map(p => (
              <div key={p.id} className="bg-white border border-[#E5E5E0] p-6 group hover:border-black transition-colors relative">
                <div className="aspect-square bg-[#F0F0EB] mb-4 overflow-hidden">
                  <img src={p.images[0]} className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500" />
                </div>
                <div className="mb-2">
                   <div className="text-[9px] text-gray-400 uppercase tracking-widest mb-1">{(TRANSLATIONS[language].categoryTitles as any)[p.category] || p.category}</div>
                   <h4 className="font-medium text-sm">{p.name[language]}</h4>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-xs text-gray-400">{p.price > 0 ? p.price.toLocaleString() : ''} {p.price > 0 ? t.currency : ''}</span>
                  <div className="flex space-x-2">
                    <button onClick={() => setEditingProduct(p)} className="p-2 text-gray-400 hover:text-black transition-colors">
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                    </button>
                    <button onClick={() => setProducts(products.filter(pr => pr.id !== p.id))} className="p-2 text-gray-400 hover:text-red-500 transition-colors">
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'team' && isSuperAdmin && (
        <div className="max-w-2xl bg-[#F9F9F7] p-12 border border-[#E5E5E0] mx-auto">
          <div className="flex space-x-4 mb-12">
            <input 
              type="email" placeholder="admin@gmail.com"
              value={newAdminEmail} onChange={e => setNewAdminEmail(e.target.value)}
              className="flex-grow bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors"
            />
            <button 
              onClick={() => {
                if (newAdminEmail) setAdmins([...admins, { email: newAdminEmail, role: UserRole.ADMIN }]);
                setNewAdminEmail('');
              }}
              className="bg-black text-white px-8 py-3 text-[10px] font-bold tracking-widest uppercase"
            >
              Add
            </button>
          </div>
          <div className="space-y-4">
            {admins.map(admin => (
              <div key={admin.email} className="flex justify-between items-center py-4 border-b border-[#E5E5E0] last:border-0">
                <div className="text-sm font-medium">{admin.email}</div>
                <div className="text-[10px] uppercase tracking-widest font-bold text-gray-300">{admin.role}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {editingProduct && (
        <div className="fixed inset-0 z-[60] bg-[#F9F9F7]/95 backdrop-blur overflow-y-auto">
          <div className="max-w-4xl mx-auto py-20 px-6">
            <h2 className="text-3xl font-light tracking-tight mb-12">{editingProduct.id ? t.editProduct : t.addProduct}</h2>
            <form onSubmit={saveProduct} className="grid grid-cols-1 md:grid-cols-2 gap-16">
              <div className="space-y-8">
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Название (RU)</label>
                  <input 
                    required value={editingProduct.name?.[Language.RU]} 
                    onChange={e => setEditingProduct({...editingProduct, name: {...editingProduct.name!, [Language.RU]: e.target.value}} as any)}
