            />
            <div className="absolute bottom-8 left-0 right-0 flex justify-center space-x-8">
              <button 
                onClick={closeCamera}
                className="bg-white/10 backdrop-blur-md text-white px-8 py-3 rounded-full text-xs font-bold tracking-widest uppercase hover:bg-white/20 transition-all border border-white/20"
              >
                {t.cancel}
              </button>
              <button 
                onClick={capturePhoto}
                className="bg-white text-black w-16 h-16 rounded-full flex items-center justify-center hover:scale-110 active:scale-95 transition-all shadow-xl"
