                <div className="flex justify-between items-center">
                  <h4 className="text-sm font-light">{p.name[language]}</h4>
                  <span className="text-[10px] font-medium text-gray-500">
                    {p.price > 0 ? `${p.price.toLocaleString()} ${t.currency}` : ''}
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
