        <div className="flex space-x-8">
          <button onClick={() => setActiveTab('products')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'products' ? 'border-black' : 'border-transparent text-gray-300'}`}>{t.catalog}</button>
          {isSuperAdmin && <button onClick={() => setActiveTab('team')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'team' ? 'border-black' : 'border-transparent text-gray-300'}`}>{t.team}</button>}
        </div>
      </div>

      {activeTab === 'products' && (
        <div className="space-y-12">
          <div className="flex justify-end">
            <button onClick={() => setEditingProduct({ name: { [Language.RU]: '', [Language.UZ]: '' }, description: { [Language.RU]: '', [Language.UZ]: '' }, price: 0, images: [], category: CATEGORIES[0], materialType: 'Teak', dimensions: '', materialDetail: { [Language.RU]: '', [Language.UZ]: '' }, inStock: true })} className="bg-black text-white px-8 py-3 text-[10px] font-bold tracking-widest uppercase">+ {t.addProduct}</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {products.map(p => (
              <div key={p.id} className="bg-white border border-[#E5E5E0] p-6 group hover:border-black transition-colors relative rounded-sm">
                <div className="aspect-square bg-[#F0F0EB] mb-4 overflow-hidden rounded-sm">
                  <img src={p.images[0]} className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500" />
                </div>
                <h4 className="font-medium text-sm mb-1">{p.name[language]}</h4>
                <div className="flex justify-between items-center mt-4">
                  <span className="text-xs text-gray-400 font-medium">{p.price > 0 ? `${p.price.toLocaleString()} ${t.currency}` : ''}</span>
                  <div className="flex space-x-2">
                    <button onClick={() => setEditingProduct(p)} className="p-2 text-gray-400 hover:text-black transition-colors"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
                    <button onClick={() => setProducts(products.filter(pr => pr.id !== p.id))} className="p-2 text-gray-400 hover:text-red-500 transition-colors"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {editingProduct && (
        <div className="fixed inset-0 z-[60] bg-[#F9F9F7]/98 backdrop-blur overflow-y-auto p-6 md:p-12">
          <div className="max-w-4xl mx-auto py-10">
            <h2 className="text-3xl font-light tracking-tight mb-12">{editingProduct.id ? t.editProduct : t.addProduct}</h2>
            <form onSubmit={saveProduct} className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="space-y-8">
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Название (RU)</label>
                  <input required value={editingProduct.name?.[Language.RU]} onChange={e => setEditingProduct({...editingProduct, name: {...editingProduct.name!, [Language.RU]: e.target.value}} as any)} className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors" />
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">{t.categories}</label>
                  <select value={editingProduct.category} onChange={e => setEditingProduct({...editingProduct, category: e.target.value})} className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none">{CATEGORIES.map(cat => (<option key={cat} value={cat}>{(TRANSLATIONS[Language.RU].categoryTitles as any)[cat] || cat}</option>))}</select>
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-4">{t.imageUpload}</label>
                  <div className="grid grid-cols-3 gap-3">
                    {editingProduct.images?.map((img, idx) => (
                      <div key={idx} className="relative aspect-square bg-gray-100 rounded-sm overflow-hidden group">
                        <img src={img} className="w-full h-full object-cover" />
                        <button type="button" onClick={() => setEditingProduct({...editingProduct, images: editingProduct.images?.filter((_, i) => i !== idx)})} className="absolute inset-0 flex items-center justify-center bg-black/40 text-white opacity-0 group-hover:opacity-100 transition-opacity"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
                      </div>
                    ))}
                    <div className="flex flex-col gap-2">
                      <label className="aspect-square border-2 border-dashed border-[#E5E5E0] rounded-sm flex items-center justify-center cursor-pointer hover:border-black transition-colors"><svg className="w-5 h-5 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg><input type="file" multiple accept="image/*" className="hidden" onChange={handleImageUpload} /></label>
                      <button type="button" onClick={openCamera} className="aspect-square border-2 border-dashed border-[#E5E5E0] rounded-sm flex items-center justify-center hover:border-black transition-colors"><svg className="w-5 h-5 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg></button>
                    </div>
                  </div>
                </div>
              </div>
              <div className="space-y-8">
                <div>
                  <div className="flex justify-between items-center mb-2"><label className="text-[10px] font-bold tracking-widest uppercase text-gray-400">Описание (RU)</label><button type="button" onClick={() => handleGenerateAI(Language.RU)} disabled={isGenerating} className="text-[10px] font-bold text-gray-400 hover:text-black transition-colors uppercase">{isGenerating ? '...' : t.aiGenerate}</button></div>
                  <textarea value={editingProduct.description?.[Language.RU]} onChange={e => setEditingProduct({...editingProduct, description: {...editingProduct.description!, [Language.RU]: e.target.value}} as any)} className="w-full bg-[#F0F0EB] p-4 text-sm focus:outline-none rounded-sm" rows={4} />
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">{t.price}</label>
                  <input type="number" value={editingProduct.price || ''} onChange={e => setEditingProduct({...editingProduct, price: Number(e.target.value)})} className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors" />
                </div>
                <div className="flex space-x-4 pt-10">
                  <button type="submit" className="flex-grow bg-black text-white py-5 text-[10px] font-bold tracking-widest uppercase rounded-sm">Save</button>
                  <button type="button" onClick={() => setEditingProduct(null)} className="px-10 border border-[#E5E5E0] py-5 text-[10px] font-bold tracking-widest uppercase rounded-sm">Close</button>
                </div>
              </div>
            </form>
          </div>
        </div>
      )}

      {isCameraOpen && (
        <div className="fixed inset-0 z-[100] bg-black/95 flex flex-col items-center justify-center p-4">
          <div className="relative w-full max-w-lg aspect-[3/4] bg-gray-900 overflow-hidden shadow-2xl rounded-2xl">
            <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
            <div className="absolute bottom-10 left-0 right-0 flex justify-center space-x-12 items-center">
              <button onClick={closeCamera} className="bg-white/10 backdrop-blur text-white px-6 py-2 rounded-full text-[10px] font-bold tracking-widest uppercase border border-white/20">{t.cancel}</button>
              <button onClick={capturePhoto} className="bg-white w-20 h-20 rounded-full flex items-center justify-center shadow-xl border-4 border-gray-200 active:scale-90 transition-transform"><div className="w-14 h-14 rounded-full border-2 border-black" /></button>
            </div>
          </div>
          <canvas ref={canvasRef} className="hidden" />
        </div>
      )}
    </div>
  );
};

