/**
 * Формирует сообщение и перенаправляет пользователя в Telegram.
 */
export const submitOrder = async (product: Product, customer: OrderData): Promise<boolean> => {
  return new Promise((resolve) => {
    // Подготовка текста сообщения
    const message = `
🌟 *НОВЫЙ ЗАКАЗ: ASIA FURNITURE*
-------------------------
🪑 *Товар:* ${product.name[Language.RU]}
🏷️ *Категория:* ${product.category}
💰 *Цена:* ${product.price.toLocaleString()} сум
📏 *Габариты:* ${product.dimensions}
-------------------------
👤 *Клиент:* ${customer.name}
📞 *Телефон:* ${customer.phone}
📧 *Email:* ${customer.email}
-------------------------
_Сформировано через каталог_
    `.trim();

    // Кодируем текст для URL
    const encodedText = encodeURIComponent(message);

    // В Telegram прямая ссылка с текстом для номера телефона реализуется через t.me
    // Примечание: Telegram Desktop и мобильные приложения по-разному обрабатывают ?text=
    // Самый универсальный способ для "отправить сообщение конкретному номеру" - это t.me/<номер>
    // Однако автоматическая вставка текста работает лучше через бота или публичную ссылку.
    // Мы используем формат, который предложит пользователю отправить текст в чат.

    const telegramUrl = `https://t.me/share/url?url=${encodeURIComponent(window.location.origin)}&text=${encodedText}`;

    // Если нужно именно на конкретный номер, открываем чат с номером:
    const directChatUrl = `https://t.me/${ADMIN_TELEGRAM_NUMBER.replace('+', '')}`;

    // Логика: Сначала показываем консоль для отладки
    console.log(`[TELEGRAM REDIRECT] Отправка сообщения на ${ADMIN_TELEGRAM_NUMBER}`);

    // Мы открываем окно шаринга, где пользователь выберет чат (или чат будет предложен, если t.me поддерживает контекст)
    // Либо открываем чат напрямую. Для бизнес-задач в Узб чаще всего используют переход в чат.

    window.open(telegramUrl, '_blank');

    setTimeout(() => {
      resolve(true);
    }, 500);
  });
};

