export interface OrderData {
  name: string;
  phone: string;
  email: string;
}

/**
 * Формирует сообщение и перенаправляет пользователя в Telegram.
 */
export const submitOrder = async (product: Product, customer: OrderData): Promise<boolean> => {
  return new Promise((resolve) => {
    // Подготовка текста сообщения
    const message = `
🌟 *НОВЫЙ ЗАКАЗ: ASIA FURNITURE*
-------------------------
🪑 *Товар:* ${product.name[Language.RU]}
🏷️ *Категория:* ${product.category}
💰 *Цена:* ${product.price.toLocaleString()} сум
📏 *Габариты:* ${product.dimensions}
-------------------------
👤 *Клиент:* ${customer.name}
📞 *Телефон:* ${customer.phone}
📧 *Email:* ${customer.email}
-------------------------
_Сформировано через каталог_
    `.trim();

    // Кодируем текст для URL
    const encodedText = encodeURIComponent(message);

    // Пытаемся открыть чат напрямую. 
    // t.me/phone_number не поддерживает автоматическую вставку текста (?text=)
    // t.me/share/url - поддерживает, но требует выбора чата.
    // Мы сначала копируем текст в буфер обмена (для удобства пользователя), 
    // а затем открываем чат с админом.

    try {
      navigator.clipboard.writeText(message);
    } catch (e) {
      console.warn("Clipboard failed");
    }

    const cleanNumber = ADMIN_TELEGRAM_NUMBER.replace(/[^\d]/g, '');
    const directUrl = `https://t.me/+${cleanNumber}`;
    const shareUrl = `https://t.me/share/url?url=${encodeURIComponent('ASIA FURNITURE')}&text=${encodedText}`;

    // Открываем окно шаринга, так как оно позволяет сразу увидеть текст. 
    // Пользователю останется только нажать на контакт админа в списке (который будет вверху, если они общались).
    window.open(shareUrl, '_blank');

    setTimeout(() => {
      resolve(true);
    }, 500);
  });
};

import React, { useState, useRef, useEffect } from 'react';
import { Product, AdminUser, UserRole, Language, MaterialType } from '../types';
import { CATEGORIES, TRANSLATIONS } from '../constants';
import { generateProductDescription } from '../services/geminiService';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  admins: AdminUser[];
  setAdmins: React.Dispatch<React.SetStateAction<AdminUser[]>>;
  currentUser: AdminUser;
  language: Language;
  t: any;
  onLogout: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  products, setProducts, admins, setAdmins, currentUser, language, t, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'team'>('products');
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);
  const [newAdmin, setNewAdmin] = useState({ email: '', phone: '' });
  const [isGenerating, setIsGenerating] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const isSuperAdmin = currentUser.role === UserRole.SUPER_ADMIN;

  const saveProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;

    if (editingProduct.id) {
      setProducts(prev => prev.map(p => p.id === editingProduct.id ? (editingProduct as Product) : p));
    } else {
      const newProd: Product = {
        ...(editingProduct as Omit<Product, 'id'>),
        id: Date.now().toString(),
      };
      setProducts(prev => [newProd, ...prev]);
    }
    setEditingProduct(null);
  };

  const handleAdminAction = (email: string, action: 'promote' | 'kick' | 'demote') => {
    setAdmins(prev => {
      if (action === 'kick') return prev.filter(a => a.email !== email);
      return prev.map(a => {
        if (a.email === email) {
          return {
            ...a,
            role: action === 'promote' ? UserRole.SUPER_ADMIN : UserRole.ADMIN
          };
        }
        return a;
      });
    });
  };

  const handleLeave = () => {
    if (confirm(t.leaveAdmin + "?")) {
      handleAdminAction(currentUser.email, 'kick');
      onLogout();
    }
  };

  const addAdmin = () => {
    if (newAdmin.email) {
      setAdmins([...admins, { email: newAdmin.email, phone: newAdmin.phone, role: UserRole.ADMIN }]);
      setNewAdmin({ email: '', phone: '' });
    }
  };

  const openCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' } 
      });
      streamRef.current = stream;
      setIsCameraOpen(true);
      setTimeout(() => {
        if (videoRef.current) videoRef.current.srcObject = stream;
      }, 100);
    } catch (err) {
      console.error("Camera access denied:", err);
      alert(language === Language.RU ? "Нужен доступ к камере" : "Kameraga ruxsat kerak");
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg');
        setEditingProduct(prev => ({
          ...prev,
          images: [...(prev?.images || []), dataUrl]
        }));
        closeCamera();
      }
    }
  };

  const closeCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraOpen(false);
  };

  const handleGenerateAI = async (lang: Language) => {
    const productName = editingProduct?.name?.[lang];
    if (!productName || isGenerating) return;
    setIsGenerating(true);
    try {
      const result = await generateProductDescription(productName, lang);
      setEditingProduct(prev => ({
        ...prev,
        description: { ...(prev?.description || {}), [lang]: result }
      } as any));
    } catch (e) { console.error(e); }
    finally { setIsGenerating(false); }
  };

  return (
    <div className="max-w-7xl mx-auto px-6 py-12">
      <div className="flex justify-between items-center mb-16 border-b border-[#E5E5E0] pb-8">
        <h1 className="text-3xl font-light tracking-tight">{t.adminPanel}</h1>
        <div className="flex items-center space-x-8">
          <button onClick={() => setActiveTab('products')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'products' ? 'border-black' : 'border-transparent text-gray-300'}`}>{t.catalog}</button>
          <button onClick={() => setActiveTab('team')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'team' ? 'border-black' : 'border-transparent text-gray-300'}`}>{t.team}</button>
          {isSuperAdmin && (
            <button onClick={handleLeave} className="text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 border-transparent text-red-400 hover:text-red-600">
              {t.leaveAdmin}
            </button>
          )}
        </div>
      </div>

      {activeTab === 'products' && (
        <div className="space-y-12 animate-in fade-in duration-500">
          <div className="flex justify-end">
            <button onClick={() => setEditingProduct({ name: { [Language.RU]: '', [Language.UZ]: '' }, description: { [Language.RU]: '', [Language.UZ]: '' }, price: 0, images: [], category: CATEGORIES[0], materialType: 'Teak', dimensions: '', materialDetail: { [Language.RU]: '', [Language.UZ]: '' }, inStock: true })} className="bg-black text-white px-8 py-3 text-[10px] font-bold tracking-widest uppercase rounded-sm">+ {t.addProduct}</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {products.map(p => (
