                <div className="flex justify-between items-center mt-4">
                  <span className="text-xs text-gray-400 font-medium">{p.price > 0 ? `${p.price.toLocaleString()} ${t.currency}` : ''}</span>
                  <div className="flex space-x-2">
                    <button onClick={() => setEditingProduct(p)} className="p-2 text-gray-400 hover:text-black transition-colors"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
                    <button onClick={() => setProducts(products.filter(pr => pr.id !== p.id))} className="p-2 text-gray-400 hover:text-red-500 transition-colors"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'team' && (
        <div className="max-w-4xl mx-auto space-y-12 animate-in fade-in duration-500">
          {isSuperAdmin && (
            <div className="bg-[#F9F9F7] p-8 border border-[#E5E5E0] rounded-2xl flex flex-col md:flex-row gap-4 items-end">
              <div className="flex-grow space-y-2">
                <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400">Email</label>
                <input 
                  type="email" value={newAdmin.email} onChange={e => setNewAdmin({...newAdmin, email: e.target.value})}
                  className="w-full bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none focus:border-black"
                />
              </div>
              <div className="flex-grow space-y-2">
                <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400">Telegram Phone</label>
                <input 
                  type="text" placeholder="+998..." value={newAdmin.phone} onChange={e => setNewAdmin({...newAdmin, phone: e.target.value})}
                  className="w-full bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none focus:border-black"
                />
              </div>
              <button onClick={addAdmin} className="bg-black text-white px-8 py-3 text-[10px] font-bold tracking-widest uppercase rounded-sm">Add</button>
            </div>
          )}

          <div className="grid grid-cols-1 gap-4">
            {admins.map(admin => (
              <div key={admin.email} className="bg-white p-6 border border-[#E5E5E0] rounded-xl flex items-center justify-between group hover:border-black transition-colors">
                <div>
                  <div className="flex items-center space-x-3">
                    <span className="text-sm font-medium">{admin.email}</span>
                    <span className={`text-[8px] font-bold tracking-widest uppercase px-2 py-0.5 rounded ${admin.role === UserRole.SUPER_ADMIN ? 'bg-black text-white' : 'bg-gray-100 text-gray-500'}`}>
                      {admin.role}
                    </span>
                  </div>
                  <div className="text-[10px] text-gray-400 mt-1">{admin.phone || 'No phone'}</div>
                </div>

                {isSuperAdmin && admin.email !== currentUser.email && (
                  <div className="flex space-x-2">
                    {admin.role !== UserRole.SUPER_ADMIN && (
                      <button onClick={() => handleAdminAction(admin.email, 'promote')} className="text-[9px] font-bold tracking-widest uppercase text-blue-500 hover:text-blue-700">
                        {t.promote}
                      </button>
                    )}
                    {admin.role === UserRole.SUPER_ADMIN && (
                      <button onClick={() => handleAdminAction(admin.email, 'demote')} className="text-[9px] font-bold tracking-widest uppercase text-orange-500 hover:text-orange-700">
                        {t.demote}
                      </button>
                    )}
                    <button onClick={() => handleAdminAction(admin.email, 'kick')} className="text-[9px] font-bold tracking-widest uppercase text-red-500 hover:text-red-700">
                      {t.delete}
                    </button>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {editingProduct && (
        <div className="fixed inset-0 z-[60] bg-[#F9F9F7]/98 backdrop-blur overflow-y-auto p-6 md:p-12">
          <div className="max-w-4xl mx-auto py-10">
            <h2 className="text-3xl font-light tracking-tight mb-12">{editingProduct.id ? t.editProduct : t.addProduct}</h2>
            <form onSubmit={saveProduct} className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="space-y-8">
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Название (RU)</label>
                  <input required value={editingProduct.name?.[Language.RU]} onChange={e => setEditingProduct({...editingProduct, name: {...editingProduct.name!, [Language.RU]: e.target.value}} as any)} className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors" />
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">{t.categories}</label>
                  <select value={editingProduct.category} onChange={e => setEditingProduct({...editingProduct, category: e.target.value})} className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none">{CATEGORIES.map(cat => (<option key={cat} value={cat}>{(TRANSLATIONS[Language.RU].categoryTitles as any)[cat] || cat}</option>))}</select>
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-4">{t.imageUpload}</label>
                  <div className="grid grid-cols-3 gap-3">
                    {editingProduct.images?.map((img, idx) => (
                      <div key={idx} className="relative aspect-square bg-gray-100 rounded-sm overflow-hidden group">
                        <img src={img} className="w-full h-full object-cover" />
                        <button type="button" onClick={() => setEditingProduct({...editingProduct, images: editingProduct.images?.filter((_, i) => i !== idx)})} className="absolute inset-0 flex items-center justify-center bg-black/40 text-white opacity-0 group-hover:opacity-100 transition-opacity"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
                      </div>
                    ))}
                    <div className="flex flex-col gap-2">
                      <label className="aspect-square border-2 border-dashed border-[#E5E5E0] rounded-sm flex items-center justify-center cursor-pointer hover:border-black transition-colors"><svg className="w-5 h-5 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg><input type="file" multiple accept="image/*" className="hidden" onChange={(e) => {
                        const files = e.target.files;
                        if (!files) return;
                        Array.from(files).forEach(file => {
                          const reader = new FileReader();
                          reader.onloadend = () => setEditingProduct(prev => ({...prev, images: [...(prev?.images || []), reader.result as string]} as any));
                          reader.readAsDataURL(file);
                        });
                      }} /></label>
                      <button type="button" onClick={openCamera} className="aspect-square border-2 border-dashed border-[#E5E5E0] rounded-sm flex items-center justify-center hover:border-black transition-colors"><svg className="w-5 h-5 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg></button>
                    </div>
                  </div>
                </div>
              </div>
              <div className="space-y-8">
                <div>
                  <div className="flex justify-between items-center mb-2"><label className="text-[10px] font-bold tracking-widest uppercase text-gray-400">Описание (RU)</label><button type="button" onClick={() => handleGenerateAI(Language.RU)} disabled={isGenerating} className="text-[10px] font-bold text-gray-400 hover:text-black transition-colors uppercase">{isGenerating ? '...' : t.aiGenerate}</button></div>
                  <textarea value={editingProduct.description?.[Language.RU]} onChange={e => setEditingProduct({...editingProduct, description: {...editingProduct.description!, [Language.RU]: e.target.value}} as any)} className="w-full bg-[#F0F0EB] p-4 text-sm focus:outline-none rounded-sm" rows={4} />
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">{t.price}</label>
                  <input type="number" value={editingProduct.price || ''} onChange={e => setEditingProduct({...editingProduct, price: Number(e.target.value)})} className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black transition-colors" />
                </div>
                <div className="flex space-x-4 pt-10">
                  <button type="submit" className="flex-grow bg-black text-white py-5 text-[10px] font-bold tracking-widest uppercase rounded-sm">Save</button>
                  <button type="button" onClick={() => setEditingProduct(null)} className="px-10 border border-[#E5E5E0] py-5 text-[10px] font-bold tracking-widest uppercase rounded-sm">Close</button>
                </div>
              </div>
            </form>
          </div>
        </div>
      )}

      {isCameraOpen && (
        <div className="fixed inset-0 z-[100] bg-black/95 flex flex-col items-center justify-center p-4">
          <div className="relative w-full max-lg aspect-[3/4] bg-gray-900 overflow-hidden shadow-2xl rounded-2xl">
            <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
            <div className="absolute bottom-10 left-0 right-0 flex justify-center space-x-12 items-center">
              <button onClick={closeCamera} className="bg-white/10 backdrop-blur text-white px-6 py-2 rounded-full text-[10px] font-bold tracking-widest uppercase border border-white/20">{t.cancel}</button>
              <button onClick={capturePhoto} className="bg-white w-20 h-20 rounded-full flex items-center justify-center shadow-xl border-4 border-gray-200 active:scale-90 transition-transform"><div className="w-14 h-14 rounded-full border-2 border-black" /></button>
            </div>
          </div>
          <canvas ref={canvasRef} className="hidden" />
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import { Language, Product, AdminUser, UserRole } from './types';
import { SUPER_ADMIN_EMAIL, INITIAL_PRODUCTS, TRANSLATIONS, ADMIN_TELEGRAM_NUMBER } from './constants';
import Navbar from './components/Navbar';
import Catalog from './components/Catalog';
import ProductDetail from './components/ProductDetail';
import AdminPanel from './components/AdminPanel';
import LoginModal from './components/LoginModal';
import ProfileView from './components/ProfileView';

const App: React.FC = () => {
  const [language, setLanguage] = useState<Language>(Language.RU);
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('iboolimi_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });
  const [admins, setAdmins] = useState<AdminUser[]>(() => {
    const saved = localStorage.getItem('iboolimi_admins');
    return saved ? JSON.parse(saved) : [{ email: SUPER_ADMIN_EMAIL, role: UserRole.SUPER_ADMIN, phone: ADMIN_TELEGRAM_NUMBER }];
  });
  const [currentUser, setCurrentUser] = useState<AdminUser | null>(() => {
    const saved = sessionStorage.getItem('iboolimi_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [view, setView] = useState<{ type: 'catalog' | 'detail' | 'admin' | 'profile', productId?: string }>({ type: 'catalog' });
  const [showLogin, setShowLogin] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    localStorage.setItem('iboolimi_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('iboolimi_admins', JSON.stringify(admins));
  }, [admins]);

  const handleLogin = (email: string) => {
    const foundAdmin = admins.find(a => a.email.toLowerCase() === email.toLowerCase());
    if (foundAdmin) {
      setCurrentUser(foundAdmin);
      sessionStorage.setItem('iboolimi_session', JSON.stringify(foundAdmin));
    } else {
      // Regular user login
      const user = { email, role: UserRole.USER };
      setCurrentUser(user);
      sessionStorage.setItem('iboolimi_session', JSON.stringify(user));
    }
    setShowLogin(false);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    sessionStorage.removeItem('iboolimi_session');
    setView({ type: 'catalog' });
  };

  const t = TRANSLATIONS[language];

  const handleUserIconClick = () => {
    if (!currentUser) {
      setShowLogin(true);
    } else if (currentUser.role === UserRole.USER) {
      setView({ type: 'profile' });
    } else {
      setView({ type: 'admin' });
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        language={language} 
        setLanguage={setLanguage}
        onAdminClick={handleUserIconClick}
        onHomeClick={() => setView({ type: 'catalog' })}
        currentUser={currentUser}
        onLogout={handleLogout}
        t={t}
      />

      <main className="flex-grow">
        {view.type === 'catalog' && (
          <Catalog 
            products={products} 
            language={language} 
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            onProductClick={(id) => setView({ type: 'detail', productId: id })}
            t={t}
          />
        )}

        {view.type === 'detail' && view.productId && (
          <ProductDetail 
            product={products.find(p => p.id === view.productId)!}
            allProducts={products}
            language={language}
            onBack={() => setView({ type: 'catalog' })}
            onProductClick={(id) => setView({ type: 'detail', productId: id })}
            t={t}
          />
        )}

        {view.type === 'admin' && currentUser && (currentUser.role === UserRole.ADMIN || currentUser.role === UserRole.SUPER_ADMIN) && (
          <AdminPanel 
            products={products}
            setProducts={setProducts}
            admins={admins}
            setAdmins={setAdmins}
            currentUser={currentUser}
            language={language}
            t={t}
            onLogout={handleLogout}
          />
        )}

        {view.type === 'profile' && currentUser && (
          <ProfileView 
            currentUser={currentUser}
            language={language}
            t={t}
          />
        )}
      </main>

      <footer className="bg-gray-900 text-white py-12 px-6 mt-20">
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-3 gap-12 text-center md:text-left">
          <div>
            <h3 className="text-2xl font-light tracking-[0.3em] mb-4">ASIA FURNITURE</h3>
            <p className="text-gray-400 text-sm leading-relaxed">Премиальная мебель для вашего дома в Узбекистане.</p>
          </div>
          <div>
            <h4 className="text-[10px] font-bold tracking-widest uppercase mb-4 text-gray-500">{t.categories}</h4>
            <ul className="text-gray-400 text-sm space-y-3">
              {Object.keys(t.categoryTitles).map(key => (
                <li key={key} className="hover:text-white cursor-pointer transition-colors" onClick={() => setView({ type: 'catalog' })}>
                  {(t.categoryTitles as any)[key]}
                </li>
              ))}
            </ul>
          </div>
          <div>
            <h4 className="text-[10px] font-bold tracking-widest uppercase mb-4 text-gray-500">Contact</h4>
            <p className="text-gray-400 text-sm">iboolimi@gmail.com</p>
            <p className="text-gray-400 text-sm">{ADMIN_TELEGRAM_NUMBER}</p>
          </div>
        </div>
        <div className="mt-20 pt-8 border-t border-gray-800 text-center text-gray-500 text-[10px] uppercase tracking-widest">
          &copy; {new Date().getFullYear()} ASIA FURNITURE. All rights reserved.
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Product, AdminUser, UserRole, Language, MaterialType } from '../types';
import { CATEGORIES, TRANSLATIONS } from '../constants';
import { generateProductDescription } from '../services/geminiService';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  admins: AdminUser[];
  setAdmins: React.Dispatch<React.SetStateAction<AdminUser[]>>;
  currentUser: AdminUser;
  language: Language;
  t: any;
  onLogout: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  products, setProducts, admins, setAdmins, currentUser, language, t, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'team'>('products');
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);
  const [newAdmin, setNewAdmin] = useState({ email: '', phone: '' });
  const [isGenerating, setIsGenerating] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const isSuperAdmin = currentUser.role === UserRole.SUPER_ADMIN;

  const saveProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;

    if (editingProduct.id) {
      setProducts(prev => prev.map(p => p.id === editingProduct.id ? (editingProduct as Product) : p));
    } else {
      const newProd: Product = {
        ...(editingProduct as Omit<Product, 'id'>),
        id: Date.now().toString(),
      };
      setProducts(prev => [newProd, ...prev]);
    }
    setEditingProduct(null);
  };

  const handleAdminAction = (email: string, action: 'promote' | 'kick' | 'demote') => {
    setAdmins(prev => {
      if (action === 'kick') return prev.filter(a => a.email !== email);
      return prev.map(a => {
        if (a.email === email) {
          return {
            ...a,
            role: action === 'promote' ? UserRole.SUPER_ADMIN : UserRole.ADMIN
          };
        }
        return a;
      });
    });
  };

  const handleLeave = () => {
    if (confirm(t.leaveAdmin + "?")) {
      handleAdminAction(currentUser.email, 'kick');
      onLogout();
    }
  };

  const addAdmin = () => {
    if (newAdmin.email) {
      setAdmins([...admins, { email: newAdmin.email, phone: newAdmin.phone, role: UserRole.ADMIN }]);
      setNewAdmin({ email: '', phone: '' });
    }
  };

  const openCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' } 
      });
      streamRef.current = stream;
      setIsCameraOpen(true);
      setTimeout(() => {
        if (videoRef.current) videoRef.current.srcObject = stream;
      }, 100);
    } catch (err) {
      console.error("Camera access denied:", err);
      alert(language === Language.RU ? "Нужен доступ к камере" : "Kameraga ruxsat kerak");
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg');
        setEditingProduct(prev => ({
          ...prev,
          images: [...(prev?.images || []), dataUrl]
        }));
        closeCamera();
      }
    }
  };

  const closeCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraOpen(false);
  };

  const handleGenerateAI = async (lang: Language) => {
    const productName = editingProduct?.name?.[lang];
    if (!productName || isGenerating) return;
    setIsGenerating(true);
    try {
      const result = await generateProductDescription(productName, lang);
      setEditingProduct(prev => ({
        ...prev,
        description: { ...(prev?.description || {}), [lang]: result }
      } as any));
    } catch (e) { console.error(e); }
    finally { setIsGenerating(false); }
  };

  return (
    <div className="max-w-7xl mx-auto px-6 py-12">
      <div className="flex justify-between items-center mb-16 border-b border-[#E5E5E0] pb-8">
        <h1 className="text-3xl font-light tracking-tight">{t.adminPanel}</h1>
        <div className="flex items-center space-x-8">
          <button onClick={() => setActiveTab('products')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'products' ? 'border-black' : 'border-transparent text-gray-300'}`}>{t.catalog}</button>
          <button onClick={() => setActiveTab('team')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'team' ? 'border-black' : 'border-transparent text-gray-300'}`}>{t.team}</button>
          {isSuperAdmin && (
            <button onClick={handleLeave} className="text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 border-transparent text-red-400 hover:text-red-600">
              {t.leaveAdmin}
            </button>
          )}
        </div>
      </div>

      {activeTab === 'products' && (
        <div className="space-y-12 animate-in fade-in duration-500">
          <div className="flex justify-end">
            <button onClick={() => setEditingProduct({ name: { [Language.RU]: '', [Language.UZ]: '' }, description: { [Language.RU]: '', [Language.UZ]: '' }, price: 0, images: [], category: CATEGORIES[0], materialType: 'Teak', dimensions: '', materialDetail: { [Language.RU]: '', [Language.UZ]: '' }, inStock: true })} className="bg-black text-white px-8 py-3 text-[10px] font-bold tracking-widest uppercase rounded-sm">+ {t.addProduct}</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {products.map(p => (
              <div key={p.id} className="bg-white border border-[#E5E5E0] p-6 group hover:border-black transition-colors relative rounded-sm">
                <div className="aspect-square bg-[#F0F0EB] mb-4 overflow-hidden rounded-sm">
                  <img src={p.images[0]} className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500" />
                </div>
                <h4 className="font-medium text-sm mb-1">{p.name[language]}</h4>
                <div className="flex justify-between items-center mt-4">
                  <span className="text-xs text-gray-400 font-medium">{p.price > 0 ? `${p.price.toLocaleString()} ${t.currency}` : ''}</span>
                  <div className="flex space-x-2">
                    <button onClick={() => setEditingProduct(p)} className="p-2 text-gray-400 hover:text-black transition-colors"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
                    <button onClick={() => setProducts(products.filter(pr => pr.id !== p.id))} className="p-2 text-gray-400 hover:text-red-500 transition-colors"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'team' && (
