                  <div className="flex space-x-4">
                    {admin.role !== UserRole.SUPER_ADMIN && <button onClick={() => handleAdminAction(admin.email, 'promote')} className="text-[9px] font-bold uppercase text-blue-500">{t.promote}</button>}
                    {admin.role === UserRole.SUPER_ADMIN && <button onClick={() => handleAdminAction(admin.email, 'demote')} className="text-[9px] font-bold uppercase text-orange-500">{t.demote}</button>}
                    <button onClick={() => handleAdminAction(admin.email, 'kick')} className="text-[9px] font-bold uppercase text-red-500">{t.delete}</button>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'settings' && (
        <div className="max-w-2xl mx-auto bg-white p-12 border border-[#E5E5E0] rounded-2xl animate-in fade-in">
          <h2 className="text-xl font-light mb-8">Настройка Telegram Бота</h2>
          <div className="space-y-6">
            <div>
              <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Bot API Token</label>
              <input type="password" value={botToken} onChange={e => setBotToken(e.target.value)} className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none focus:border-black" placeholder="712345678:AAEg..." />
            </div>
            <div className="flex space-x-4">
              <button onClick={saveBotToken} className="flex-grow bg-black text-white py-4 text-[10px] font-bold uppercase tracking-widest">Сохранить</button>
              <button onClick={testBot} disabled={isTestingBot} className="px-8 border border-black py-4 text-[10px] font-bold uppercase tracking-widest hover:bg-black hover:text-white transition-all disabled:opacity-50">
                {isTestingBot ? "Проверка..." : "Проверить связь"}
              </button>
            </div>
            <div className="p-6 bg-gray-50 rounded-xl text-xs text-gray-500 leading-relaxed border border-gray-100">
              <p className="font-bold mb-2 text-black">Как запустить систему:</p>
              1. Напишите <strong>/start</strong> боту @BotFather и создайте нового бота.<br/>
              2. Скопируйте <strong>API Token</strong> и вставьте его выше.<br/>
              3. <strong>Важно:</strong> Каждый администратор должен написать вашему боту /start в Telegram.<br/>
              4. Узнайте свой Chat ID (через @userinfobot) и добавьте его в разделе <strong>"Команда"</strong> для вашего email.
            </div>
          </div>
        </div>
      )}

      {editingProduct && (
        <div className="fixed inset-0 z-[60] bg-[#F9F9F7]/98 backdrop-blur overflow-y-auto p-6 md:p-12">
          <div className="max-w-4xl mx-auto py-10">
            <h2 className="text-3xl font-light mb-12">{editingProduct.id ? t.editProduct : t.addProduct}</h2>
            <form onSubmit={(e) => { e.preventDefault(); if (editingProduct.id) setProducts(prev => prev.map(p => p.id === editingProduct.id ? (editingProduct as Product) : p)); else setProducts(prev => [{...editingProduct, id: Date.now().toString()} as Product, ...prev]); setEditingProduct(null); }} className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="space-y-8">
                <div><label className="text-[10px] font-bold uppercase text-gray-400 block mb-2">Название (RU)</label><input required value={editingProduct.name?.[Language.RU]} onChange={e => setEditingProduct({...editingProduct, name: {...editingProduct.name!, [Language.RU]: e.target.value}} as any)} className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none" /></div>
                <div><label className="text-[10px] font-bold uppercase text-gray-400 block mb-4">Фото</label><div className="flex gap-2"><button type="button" onClick={openCamera} className="w-12 h-12 border-2 border-dashed border-[#E5E5E0] flex items-center justify-center text-gray-400">+</button>{editingProduct.images?.map((img, i) => <img key={i} src={img} className="w-12 h-12 object-cover" />)}</div></div>
              </div>
              <div className="space-y-8">
                <div><label className="text-[10px] font-bold uppercase text-gray-400 block mb-2">Цена</label><input type="number" value={editingProduct.price || ''} onChange={e => setEditingProduct({...editingProduct, price: Number(e.target.value)})} className="w-full bg-transparent border-b border-[#E5E5E0] py-3 text-sm focus:outline-none" /></div>
                <div className="flex space-x-4 pt-10"><button type="submit" className="flex-grow bg-black text-white py-4 text-[10px] font-bold uppercase">Сохранить</button><button type="button" onClick={() => setEditingProduct(null)} className="px-8 border border-[#E5E5E0] py-4 text-[10px] font-bold uppercase">Отмена</button></div>
              </div>
            </form>
          </div>
        </div>
      )}

      {isCameraOpen && (
        <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-4">
          <video ref={videoRef} autoPlay playsInline className="w-full max-w-lg aspect-[3/4] object-cover rounded-2xl mb-8" />
          <div className="flex space-x-8"><button onClick={closeCamera} className="text-white text-xs uppercase font-bold tracking-widest">Закрыть</button><button onClick={capturePhoto} className="w-20 h-20 bg-white rounded-full border-4 border-gray-400" /></div>
          <canvas ref={canvasRef} className="hidden" />
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import { Language, Product, AdminUser, UserRole } from './types';
import { SUPER_ADMIN_EMAIL, INITIAL_PRODUCTS, TRANSLATIONS, ADMIN_TELEGRAM_NUMBER } from './constants';
import Navbar from './components/Navbar';
import Catalog from './components/Catalog';
import ProductDetail from './components/ProductDetail';
import AdminPanel from './components/AdminPanel';
import LoginModal from './components/LoginModal';
import ProfileView from './components/ProfileView';

const App: React.FC = () => {
  const [language, setLanguage] = useState<Language>(Language.RU);
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('iboolimi_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });
  const [admins, setAdmins] = useState<AdminUser[]>(() => {
    const saved = localStorage.getItem('iboolimi_admins');
    return saved ? JSON.parse(saved) : [{ email: SUPER_ADMIN_EMAIL, role: UserRole.SUPER_ADMIN, phone: ADMIN_TELEGRAM_NUMBER }];
  });
  const [currentUser, setCurrentUser] = useState<AdminUser | null>(() => {
    const saved = sessionStorage.getItem('iboolimi_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [view, setView] = useState<{ type: 'catalog' | 'detail' | 'admin' | 'profile', productId?: string }>({ type: 'catalog' });
  const [showLogin, setShowLogin] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    localStorage.setItem('iboolimi_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('iboolimi_admins', JSON.stringify(admins));
    // Синхронизируем currentUser если он есть в списке админов
    if (currentUser) {
      const updated = admins.find(a => a.email === currentUser.email);
      if (updated && JSON.stringify(updated) !== JSON.stringify(currentUser)) {
        setCurrentUser(updated);
        sessionStorage.setItem('iboolimi_session', JSON.stringify(updated));
      }
    }
  }, [admins, currentUser]);

  const handleLogin = (email: string) => {
    const foundAdmin = admins.find(a => a.email.toLowerCase() === email.toLowerCase());
    if (foundAdmin) {
      setCurrentUser(foundAdmin);
      sessionStorage.setItem('iboolimi_session', JSON.stringify(foundAdmin));
    } else {
      const user = { email, role: UserRole.USER };
      setCurrentUser(user);
      sessionStorage.setItem('iboolimi_session', JSON.stringify(user));
    }
    setShowLogin(false);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    sessionStorage.removeItem('iboolimi_session');
    setView({ type: 'catalog' });
  };

  const t = TRANSLATIONS[language];

  const handleUserIconClick = () => {
    if (!currentUser) {
      setShowLogin(true);
    } else if (currentUser.role === UserRole.USER) {
      setView({ type: 'profile' });
    } else {
      setView({ type: 'admin' });
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        language={language} 
        setLanguage={setLanguage}
        onAdminClick={handleUserIconClick}
        onHomeClick={() => setView({ type: 'catalog' })}
        currentUser={currentUser}
        onLogout={handleLogout}
        t={t}
      />

      <main className="flex-grow">
        {view.type === 'catalog' && (
          <Catalog 
            products={products} 
            language={language} 
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            onProductClick={(id) => setView({ type: 'detail', productId: id })}
            t={t}
          />
        )}

        {view.type === 'detail' && view.productId && (
          <ProductDetail 
            product={products.find(p => p.id === view.productId)!}
            allProducts={products}
            language={language}
            onBack={() => setView({ type: 'catalog' })}
            onProductClick={(id) => setView({ type: 'detail', productId: id })}
            t={t}
          />
        )}

        {view.type === 'admin' && currentUser && (currentUser.role === UserRole.ADMIN || currentUser.role === UserRole.SUPER_ADMIN) && (
          <AdminPanel 
            products={products}
            setProducts={setProducts}
            admins={admins}
            setAdmins={setAdmins}
            currentUser={currentUser}
            language={language}
            t={t}
            onLogout={handleLogout}
          />
        )}

        {view.type === 'profile' && currentUser && (
          <ProfileView 
            currentUser={currentUser}
            language={language}
            t={t}
          />
        )}
      </main>

      {showLogin && (
        <LoginModal 
          onLogin={handleLogin} 
          onClose={() => setShowLogin(false)} 
          t={t} 
        />
      )}

      <footer className="bg-gray-900 text-white py-12 px-6 mt-20">
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-3 gap-12 text-center md:text-left">
          <div>
            <h3 className="text-2xl font-light tracking-[0.3em] mb-4">ASIA FURNITURE</h3>
            <p className="text-gray-400 text-sm leading-relaxed">Премиальная мебель для вашего дома в Узбекистане.</p>
          </div>
          <div>
            <h4 className="text-[10px] font-bold tracking-widest uppercase mb-4 text-gray-500">{t.categories}</h4>
            <ul className="text-gray-400 text-sm space-y-3">
              {Object.keys(t.categoryTitles).map(key => (
                <li key={key} className="hover:text-white cursor-pointer transition-colors" onClick={() => setView({ type: 'catalog' })}>
                  {(t.categoryTitles as any)[key]}
                </li>
              ))}
            </ul>
          </div>
          <div>
            <h4 className="text-[10px] font-bold tracking-widest uppercase mb-4 text-gray-500">Contact</h4>
            <p className="text-gray-400 text-sm">iboolimi@gmail.com</p>
            <p className="text-gray-400 text-sm">{ADMIN_TELEGRAM_NUMBER}</p>
          </div>
        </div>
        <div className="mt-20 pt-8 border-t border-gray-800 text-center text-gray-500 text-[10px] uppercase tracking-widest">
          &copy; {new Date().getFullYear()} ASIA FURNITURE. All rights reserved.
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Product, AdminUser, UserRole, Language } from '../types';
import { CATEGORIES, TRANSLATIONS } from '../constants';
import { generateProductDescription } from '../services/geminiService';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  admins: AdminUser[];
  setAdmins: React.Dispatch<React.SetStateAction<AdminUser[]>>;
  currentUser: AdminUser;
  language: Language;
  t: any;
  onLogout: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  products, setProducts, admins, setAdmins, currentUser, language, t, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'team' | 'settings' | 'my-profile'>('products');
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);
  const [newAdmin, setNewAdmin] = useState({ email: '', phone: '', chatId: '' });
  const [botToken, setBotToken] = useState(localStorage.getItem('iboolimi_bot_token') || '');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [isTestingBot, setIsTestingBot] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const isSuperAdmin = currentUser.role === UserRole.SUPER_ADMIN;

  const saveBotToken = () => {
    localStorage.setItem('iboolimi_bot_token', botToken);
    alert(language === Language.RU ? "Токен сохранен. Теперь автоматическая отправка включена." : "Token saqlandi. Endi avtomatik yuborish yoqilgan.");
  };

  const updateMyChatId = (newId: string) => {
    setAdmins(prev => prev.map(a => a.email === currentUser.email ? { ...a, telegramChatId: newId } : a));
  };

  const testBot = async () => {
    if (!botToken || !currentUser.telegramChatId) {
      alert("Сначала сохраните Токен и укажите свой Chat ID в разделе 'Мой профиль'");
      return;
    }
    setIsTestingBot(true);
    try {
      const res = await fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          chat_id: currentUser.telegramChatId,
          text: "✅ Тестовое сообщение: Бот ASIA FURNITURE настроен правильно!"
        })
      });
      if (res.ok) alert("Успешно! Проверьте свой Telegram.");
      else alert("Ошибка. Проверьте правильность токена и Chat ID.");
    } catch (e) {
      alert("Ошибка сети при проверке бота.");
    } finally {
      setIsTestingBot(false);
    }
  };

  const handleAdminAction = (email: string, action: 'promote' | 'kick' | 'demote') => {
    setAdmins(prev => {
      if (action === 'kick') {
        const remainingSupers = prev.filter(a => a.role === UserRole.SUPER_ADMIN && a.email !== email);
        if (prev.find(a => a.email === email)?.role === UserRole.SUPER_ADMIN && remainingSupers.length === 0) {
          alert("Нельзя удалить последнего главного админа!");
          return prev;
        }
        return prev.filter(a => a.email !== email);
      }
      return prev.map(a => {
        if (a.email === email) {
          return { ...a, role: action === 'promote' ? UserRole.SUPER_ADMIN : UserRole.ADMIN };
        }
        return a;
      });
    });
  };

  const handleLeave = () => {
    if (confirm(t.leaveAdmin + "?")) {
      handleAdminAction(currentUser.email, 'kick');
      onLogout();
    }
  };

  const addAdmin = () => {
    if (newAdmin.email && newAdmin.chatId) {
      setAdmins([...admins, { 
        email: newAdmin.email, 
        phone: newAdmin.phone, 
        telegramChatId: newAdmin.chatId,
        role: UserRole.ADMIN 
      }]);
      setNewAdmin({ email: '', phone: '', chatId: '' });
    } else {
      alert("Email и Chat ID обязательны для работы уведомлений!");
    }
  };

  const openCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      streamRef.current = stream;
      setIsCameraOpen(true);
      setTimeout(() => { if (videoRef.current) videoRef.current.srcObject = stream; }, 100);
    } catch (err) { console.error(err); }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const canvas = canvasRef.current;
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
      setEditingProduct(prev => ({ ...prev, images: [...(prev?.images || []), canvas.toDataURL('image/jpeg')] }));
      closeCamera();
    }
  };

  const closeCamera = () => {
    streamRef.current?.getTracks().forEach(t => t.stop());
    setIsCameraOpen(false);
  };

  return (
    <div className="max-w-7xl mx-auto px-6 py-12">
      {/* ПРЕДУПРЕЖДЕНИЕ О НАСТРОЙКЕ */}
      {(!botToken || !currentUser.telegramChatId) && (
        <div className="mb-8 bg-amber-50 border border-amber-200 p-4 rounded-xl flex items-center justify-between">
          <div className="flex items-center space-x-3 text-amber-800 text-sm">
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
            <p><strong>Внимание:</strong> {!botToken ? "Telegram Бот не настроен (Токен)." : "Ваш Chat ID не указан. Вы не будете получать уведомления."}</p>
          </div>
          <button onClick={() => setActiveTab(!botToken ? 'settings' : 'my-profile')} className="text-[10px] font-bold uppercase tracking-widest text-amber-900 underline">Исправить</button>
        </div>
      )}

      <div className="flex justify-between items-center mb-16 border-b border-[#E5E5E0] pb-8">
        <h1 className="text-3xl font-light tracking-tight">{t.adminPanel}</h1>
        <div className="flex items-center space-x-8">
          <button onClick={() => setActiveTab('products')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'products' ? 'border-black' : 'border-transparent text-gray-300'}`}>{t.catalog}</button>
          <button onClick={() => setActiveTab('team')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'team' ? 'border-black' : 'border-transparent text-gray-300'}`}>{t.team}</button>
          <button onClick={() => setActiveTab('my-profile')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'my-profile' ? 'border-black' : 'border-transparent text-gray-300'}`}>Мой профиль</button>
          <button onClick={() => setActiveTab('settings')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'settings' ? 'border-black' : 'border-transparent text-gray-300'}`}>API</button>
          <button onClick={handleLeave} className="text-[10px] font-bold tracking-widest uppercase pb-2 text-red-400 hover:text-red-600 border-b-2 border-transparent">{t.leaveAdmin}</button>
        </div>
      </div>

      {activeTab === 'products' && (
        <div className="space-y-12 animate-in fade-in duration-500">
          <div className="flex justify-end">
            <button onClick={() => setEditingProduct({ name: { [Language.RU]: '', [Language.UZ]: '' }, description: { [Language.RU]: '', [Language.UZ]: '' }, price: 0, images: [], category: CATEGORIES[0], materialType: 'Teak', dimensions: '', materialDetail: { [Language.RU]: '', [Language.UZ]: '' }, inStock: true })} className="bg-black text-white px-8 py-3 text-[10px] font-bold tracking-widest uppercase">+{t.addProduct}</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {products.map(p => (
              <div key={p.id} className="bg-white border border-[#E5E5E0] p-6 group hover:border-black transition-colors rounded-sm">
                <div className="aspect-square bg-[#F0F0EB] mb-4 overflow-hidden"><img src={p.images[0]} className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500" /></div>
                <h4 className="font-medium text-sm mb-1">{p.name[language]}</h4>
                <div className="flex justify-between items-center mt-4">
                  <span className="text-xs text-gray-400">{p.price.toLocaleString()} {t.currency}</span>
                  <div className="flex space-x-2">
                    <button onClick={() => setEditingProduct(p)} className="p-2 text-gray-400 hover:text-black"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
                    <button onClick={() => setProducts(products.filter(pr => pr.id !== p.id))} className="p-2 text-gray-400 hover:text-red-500"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'team' && (
        <div className="max-w-4xl mx-auto space-y-12 animate-in fade-in">
          {isSuperAdmin && (
            <div className="bg-[#F9F9F7] p-8 border border-[#E5E5E0] rounded-2xl space-y-4">
              <h3 className="text-xs font-bold tracking-widest uppercase">Добавить администратора</h3>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <input placeholder="Email" value={newAdmin.email} onChange={e => setNewAdmin({...newAdmin, email: e.target.value})} className="bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none" />
                <input placeholder="Telegram Chat ID" value={newAdmin.chatId} onChange={e => setNewAdmin({...newAdmin, chatId: e.target.value})} className="bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none" />
                <button onClick={addAdmin} className="bg-black text-white py-2 text-[10px] font-bold uppercase tracking-widest">Добавить</button>
              </div>
              <p className="text-[9px] text-gray-400 uppercase">Chat ID можно узнать у бота @userinfobot (обязательно для уведомлений)</p>
            </div>
          )}
