import { Product, Language, AdminUser } from '../types';

export interface OrderData {
  name: string;
  phone: string;
  email: string;
}

/**
 * Автоматически отправляет заказ всем администраторам через Telegram Bot.
 * Не требует действий от покупателя.
 */
export const submitOrder = async (product: Product, customer: OrderData): Promise<boolean> => {
  // Получаем настройки и список админов из хранилища
  const botToken = localStorage.getItem('iboolimi_bot_token');
  const admins: AdminUser[] = JSON.parse(localStorage.getItem('iboolimi_admins') || '[]');

  if (!botToken) {
    console.warn("Telegram Bot Token не настроен в панели управления.");
    return false;
  }

  const message = `
📦 *НОВЫЙ ЗАКАЗ: ASIA FURNITURE*
-------------------------
🪑 *Товар:* ${product.name[Language.RU]}
💰 *Цена:* ${product.price.toLocaleString()} сум
📏 *Габариты:* ${product.dimensions}
-------------------------
👤 *Клиент:* ${customer.name}
📞 *Телефон:* ${customer.phone}
📧 *Email:* ${customer.email}
-------------------------
_Заказ отправлен автоматически_
  `.trim();

  const recipients = admins.filter(admin => admin.telegramChatId);

  if (recipients.length === 0) {
    console.warn("Нет администраторов с указанным Telegram Chat ID.");
    return false;
  }

  const sendPromises = recipients.map(admin => {
    return fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: admin.telegramChatId,
        text: message,
        parse_mode: 'Markdown'
      })
    });
  });

  try {
    const results = await Promise.all(sendPromises);
    const someOk = results.some(res => res.ok);
    return someOk;
  } catch (error) {
    console.error("Ошибка при отправке в Telegram:", error);
    return false;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Product, AdminUser, UserRole, Language } from '../types';
import { CATEGORIES, TRANSLATIONS } from '../constants';
import { generateProductDescription } from '../services/geminiService';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  admins: AdminUser[];
  setAdmins: React.Dispatch<React.SetStateAction<AdminUser[]>>;
  currentUser: AdminUser;
  language: Language;
  t: any;
  onLogout: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  products, setProducts, admins, setAdmins, currentUser, language, t, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'team' | 'settings' | 'my-profile'>('products');
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);
  const [newAdmin, setNewAdmin] = useState({ email: '', phone: '', chatId: '' });
  const [botToken, setBotToken] = useState(localStorage.getItem('iboolimi_bot_token') || '');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [isTestingBot, setIsTestingBot] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const isSuperAdmin = currentUser.role === UserRole.SUPER_ADMIN;

  const saveBotToken = () => {
    localStorage.setItem('iboolimi_bot_token', botToken);
    alert(language === Language.RU ? "Токен сохранен. Теперь автоматическая отправка включена." : "Token saqlandi. Endi avtomatik yuborish yoqilgan.");
  };

  const updateMyChatId = (newId: string) => {
    // Clean chat ID to be numeric
    const cleanId = newId.replace(/[^0-9-]/g, '');
    setAdmins(prev => prev.map(a => a.email === currentUser.email ? { ...a, telegramChatId: cleanId } : a));
  };

  const testBot = async () => {
    if (!botToken || !currentUser.telegramChatId) {
      alert("Сначала сохраните Токен и укажите свой числовой Chat ID в разделе 'Мой профиль'");
      return;
    }
    setIsTestingBot(true);
    try {
      const res = await fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          chat_id: currentUser.telegramChatId,
          text: "✅ Тестовое сообщение: Бот ASIA FURNITURE настроен правильно!"
        })
      });
      if (res.ok) alert("Успешно! Проверьте свой Telegram.");
      else alert("Ошибка. Возможно, вы еще не написали /start боту или токен неверный.");
    } catch (e) {
      alert("Ошибка сети при проверке бота.");
    } finally {
      setIsTestingBot(false);
    }
  };

  const handleAdminAction = (email: string, action: 'promote' | 'kick' | 'demote') => {
    setAdmins(prev => {
      if (action === 'kick') {
        const remainingSupers = prev.filter(a => a.role === UserRole.SUPER_ADMIN && a.email !== email);
        if (prev.find(a => a.email === email)?.role === UserRole.SUPER_ADMIN && remainingSupers.length === 0) {
          alert("Нельзя удалить последнего главного админа!");
          return prev;
        }
        return prev.filter(a => a.email !== email);
      }
      return prev.map(a => {
        if (a.email === email) {
          return { ...a, role: action === 'promote' ? UserRole.SUPER_ADMIN : UserRole.ADMIN };
        }
        return a;
      });
    });
  };

  const handleLeave = () => {
    if (confirm(t.leaveAdmin + "?")) {
      handleAdminAction(currentUser.email, 'kick');
      onLogout();
    }
  };

  const addAdmin = () => {
    if (newAdmin.email && newAdmin.chatId) {
      setAdmins([...admins, { 
        email: newAdmin.email, 
        phone: newAdmin.phone, 
        telegramChatId: newAdmin.chatId.replace(/[^0-9-]/g, ''),
        role: UserRole.ADMIN 
      }]);
      setNewAdmin({ email: '', phone: '', chatId: '' });
    } else {
      alert("Email и числовой Chat ID обязательны!");
    }
  };

  const openCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      streamRef.current = stream;
      setIsCameraOpen(true);
      setTimeout(() => { if (videoRef.current) videoRef.current.srcObject = stream; }, 100);
    } catch (err) { 
      console.error(err); 
      alert("Не удалось получить доступ к камере. Проверьте разрешения браузера.");
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const canvas = canvasRef.current;
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
      const photoData = canvas.toDataURL('image/jpeg');

      if (editingProduct) {
        setEditingProduct(prev => ({ ...prev, images: [...(prev?.images || []), photoData] }));
      } else {
        setEditingProduct({ 
          name: { [Language.RU]: '', [Language.UZ]: '' }, 
          description: { [Language.RU]: '', [Language.UZ]: '' }, 
          price: 0, 
          images: [photoData], 
          category: CATEGORIES[0], 
          materialType: 'Teak' as any, 
          dimensions: '', 
          materialDetail: { [Language.RU]: '', [Language.UZ]: '' }, 
          inStock: true 
        });
      }
      closeCamera();
    }
  };

  const closeCamera = () => {
    streamRef.current?.getTracks().forEach(t => t.stop());
    setIsCameraOpen(false);
  };

  // Fix: Correct call to generateProductDescription using available language
  const handleGenerateAI = async (lang: Language) => {
    if (!editingProduct?.name?.[lang]) {
      alert("Сначала введите название на этом языке");
      return;
