      ...prev,
      description: { ...prev?.description, [lang]: desc }
    } as Partial<Product>));
    setIsGenerating(false);
  };

  // Fix: Logic to save or update existing product
  const handleSaveProduct = () => {
    if (!editingProduct?.name?.[Language.RU] || !editingProduct?.price) {
