            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="space-y-8">
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Название (RU)</label>
                  <input value={editingProduct.name?.[Language.RU] || ''} onChange={e => setEditingProduct({...editingProduct, name: {...editingProduct.name, [Language.RU]: e.target.value}} as any)} className="w-full bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none" />
                </div>
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Название (UZ)</label>
                  <input value={editingProduct.name?.[Language.UZ] || ''} onChange={e => setEditingProduct({...editingProduct, name: {...editingProduct.name, [Language.UZ]: e.target.value}} as any)} className="w-full bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none" />
                </div>
                <div className="flex gap-4">
                  <div className="flex-grow">
                    <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">{t.price}</label>
                    <input type="number" value={editingProduct.price || ''} onChange={e => setEditingProduct({...editingProduct, price: Number(e.target.value)})} className="w-full bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none" />
                  </div>
                  <div className="w-1/3">
                    <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Категория</label>
                    <select value={editingProduct.category} onChange={e => setEditingProduct({...editingProduct, category: e.target.value})} className="w-full bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none">
                      {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                  </div>
                </div>

                <div className="space-y-4">
                   <div className="flex items-center justify-between">
                     <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400">Описание (RU)</label>
                     <button 
                        onClick={() => handleGenerateAI(Language.RU)}
                        disabled={isGenerating}
                        className="text-[9px] font-bold text-blue-500 uppercase flex items-center gap-1 disabled:opacity-50"
                     >
                       <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                       {isGenerating ? 'GEN...' : t.aiGenerate}
                     </button>
                   </div>
                   <textarea value={editingProduct.description?.[Language.RU] || ''} onChange={e => setEditingProduct({...editingProduct, description: {...editingProduct.description, [Language.RU]: e.target.value}} as any)} className="w-full bg-[#F9F9F7] p-4 text-sm h-24 border border-[#E5E5E0] rounded-xl focus:border-black outline-none" />
                </div>

                <div className="space-y-4">
                   <div className="flex items-center justify-between">
                     <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400">Описание (UZ)</label>
                     <button 
                        onClick={() => handleGenerateAI(Language.UZ)}
                        disabled={isGenerating}
                        className="text-[9px] font-bold text-blue-500 uppercase flex items-center gap-1 disabled:opacity-50"
                     >
                       <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                       {isGenerating ? 'GEN...' : t.aiGenerate}
                     </button>
                   </div>
                   <textarea value={editingProduct.description?.[Language.UZ] || ''} onChange={e => setEditingProduct({...editingProduct, description: {...editingProduct.description, [Language.UZ]: e.target.value}} as any)} className="w-full bg-[#F9F9F7] p-4 text-sm h-24 border border-[#E5E5E0] rounded-xl focus:border-black outline-none" />
                </div>
              </div>

              <div className="space-y-8">
                <div>
                  <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-4">Фотографии</label>
                  <div className="grid grid-cols-3 gap-4 mb-6">
                    {editingProduct.images?.map((img, idx) => (
                      <div key={idx} className="relative aspect-square rounded-lg overflow-hidden border border-[#E5E5E0]">
                        <img src={img} className="w-full h-full object-cover" />
                        <button onClick={() => setEditingProduct({...editingProduct, images: editingProduct.images?.filter((_, i) => i !== idx)})} className="absolute top-1 right-1 bg-black/50 text-white rounded-full p-1"><svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
                      </div>
                    ))}
                    <label className="aspect-square flex flex-col items-center justify-center border-2 border-dashed border-[#E5E5E0] rounded-lg cursor-pointer hover:border-black transition-colors">
                      <svg className="w-6 h-6 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                      <span className="text-[8px] uppercase mt-2 text-gray-400">{t.imageUpload}</span>
                      <input type="file" multiple accept="image/*" className="hidden" onChange={e => {
                        const files = Array.from(e.target.files || []);
                        files.forEach(f => {
                          const reader = new FileReader();
                          reader.onload = (ev) => setEditingProduct(prev => ({...prev, images: [...(prev?.images || []), ev.target?.result as string]}) as any);
                          reader.readAsDataURL(f);
                        });
                      }} />
                    </label>
                  </div>
                  <button onClick={openCamera} className="w-full border border-black py-4 text-[10px] font-bold tracking-widest uppercase rounded-xl hover:bg-black hover:text-white transition-all flex items-center justify-center gap-2">
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                    {t.takePhoto}
                  </button>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">Материал (тип)</label>
                    <input value={editingProduct.materialType || ''} onChange={e => setEditingProduct({...editingProduct, materialType: e.target.value as any})} className="w-full bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none" />
                  </div>
                  <div>
                    <label className="text-[10px] font-bold tracking-widest uppercase text-gray-400 block mb-2">{t.dimensions}</label>
                    <input value={editingProduct.dimensions || ''} onChange={e => setEditingProduct({...editingProduct, dimensions: e.target.value})} className="w-full bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none" />
                  </div>
                </div>

                <button onClick={handleSaveProduct} className="w-full bg-black text-white py-6 text-[10px] font-bold tracking-widest uppercase rounded-2xl hover:bg-gray-800 transition-colors">
                  {t.save}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Full screen camera view */}
      {isCameraOpen && (
        <div className="fixed inset-0 z-[110] bg-black flex flex-col">
          <div className="flex-grow relative flex items-center justify-center">
            <video ref={videoRef} autoPlay playsInline className="max-h-full max-w-full" />
            <canvas ref={canvasRef} className="hidden" />
          </div>
          <div className="h-32 bg-black flex items-center justify-around px-8">
            <button onClick={closeCamera} className="text-white text-xs uppercase tracking-widest">{t.cancel}</button>
            <button onClick={capturePhoto} className="w-20 h-20 rounded-full border-4 border-white flex items-center justify-center">
              <div className="w-16 h-16 rounded-full bg-white active:scale-90 transition-transform" />
            </button>
            <div className="w-12" />
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useRef, useEffect } from 'react';
import { Product, AdminUser, UserRole, Language } from '../types';
import { CATEGORIES, TRANSLATIONS } from '../constants';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  admins: AdminUser[];
  setAdmins: React.Dispatch<React.SetStateAction<AdminUser[]>>;
  currentUser: AdminUser;
  language: Language;
  t: any;
  onLogout: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  products, setProducts, admins, setAdmins, currentUser, language, t, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'team' | 'settings' | 'my-profile'>('products');
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);
  const [newAdmin, setNewAdmin] = useState({ email: '', phone: '', chatId: '' });
  const [botToken, setBotToken] = useState(localStorage.getItem('iboolimi_bot_token') || '');
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [isTestingBot, setIsTestingBot] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const isSuperAdmin = currentUser.role === UserRole.SUPER_ADMIN;

  const saveBotToken = () => {
    localStorage.setItem('iboolimi_bot_token', botToken);
    alert(language === Language.RU ? "Токен сохранен." : "Token saqlandi.");
  };

  const updateMyChatId = (newId: string) => {
    const cleanId = newId.replace(/[^0-9-]/g, '');
    setAdmins(prev => prev.map(a => a.email === currentUser.email ? { ...a, telegramChatId: cleanId } : a));
  };

  const testBot = async () => {
    if (!botToken || !currentUser.telegramChatId) {
      alert("Сначала сохраните Токен и укажите свой числовой Chat ID в разделе 'Мой профиль'");
      return;
    }
    setIsTestingBot(true);
    try {
      const res = await fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          chat_id: currentUser.telegramChatId,
          text: "✅ Тестовое сообщение: Бот настроен!"
        })
      });
      if (res.ok) alert("Успешно!");
      else alert("Ошибка. Проверьте настройки.");
    } catch (e) {
      alert("Ошибка сети.");
    } finally {
      setIsTestingBot(false);
    }
  };

  const addAdmin = () => {
    if (newAdmin.email && newAdmin.chatId) {
      setAdmins([...admins, { 
        email: newAdmin.email, 
        phone: newAdmin.phone, 
        telegramChatId: newAdmin.chatId.replace(/[^0-9-]/g, ''),
        role: UserRole.ADMIN 
      }]);
      setNewAdmin({ email: '', phone: '', chatId: '' });
    } else {
      alert("Заполните поля.");
    }
  };

  const openCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      streamRef.current = stream;
      setIsCameraOpen(true);
      setTimeout(() => { if (videoRef.current) videoRef.current.srcObject = stream; }, 100);
    } catch (err) { 
      alert("Камера недоступна.");
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const canvas = canvasRef.current;
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
      const photoData = canvas.toDataURL('image/jpeg');

      if (editingProduct) {
        setEditingProduct(prev => ({ ...prev, images: [...(prev?.images || []), photoData] }));
      } else {
        setEditingProduct({ 
          name: { [Language.RU]: '', [Language.UZ]: '' }, 
          description: { [Language.RU]: '', [Language.UZ]: '' }, 
          price: 0, 
          images: [photoData], 
          category: CATEGORIES[0], 
          materialType: 'Teak', 
          dimensions: '', 
          materialDetail: { [Language.RU]: '', [Language.UZ]: '' }, 
          inStock: true 
        });
      }
      closeCamera();
    }
  };

  const closeCamera = () => {
    streamRef.current?.getTracks().forEach(t => t.stop());
    setIsCameraOpen(false);
  };

  const handleSaveProduct = () => {
    const p = editingProduct;
    if (!p?.name?.[Language.RU] || !p?.price) {
      alert("Укажите как минимум название (RU) и цену");
      return;
    }

    const finalProduct = {
      id: p.id || Date.now().toString(),
      name: p.name || { [Language.RU]: '', [Language.UZ]: '' },
      description: p.description || { [Language.RU]: '', [Language.UZ]: '' },
      price: p.price || 0,
      images: p.images || [],
      category: p.category || CATEGORIES[0],
      materialType: p.materialType || 'Teak',
      dimensions: p.dimensions || '',
      materialDetail: p.materialDetail || { [Language.RU]: '', [Language.UZ]: '' },
      inStock: p.inStock !== undefined ? p.inStock : true
    } as Product;

    if (p.id) {
      setProducts(products.map(item => item.id === p.id ? finalProduct : item));
    } else {
      setProducts([finalProduct, ...products]);
    }
    setEditingProduct(null);
  };

  return (
    <div className="max-w-7xl mx-auto px-6 py-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-16 border-b border-[#E5E5E0] pb-8 gap-6">
        <h1 className="text-3xl font-light tracking-tight">{t.adminPanel}</h1>
        <div className="flex flex-wrap items-center gap-x-8 gap-y-4">
          <button onClick={() => setActiveTab('products')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'products' ? 'border-black' : 'border-transparent text-gray-300'}`}>{t.catalog}</button>
          <button onClick={() => setActiveTab('team')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'team' ? 'border-black' : 'border-transparent text-gray-300'}`}>{t.team}</button>
          <button onClick={() => setActiveTab('my-profile')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'my-profile' ? 'border-black' : 'border-transparent text-gray-300'}`}>Мой профиль</button>
          <button onClick={() => setActiveTab('settings')} className={`text-[10px] font-bold tracking-widest uppercase pb-2 border-b-2 ${activeTab === 'settings' ? 'border-black' : 'border-transparent text-gray-300'}`}>API</button>
          <button onClick={onLogout} className="text-[10px] font-bold tracking-widest uppercase pb-2 text-red-400 hover:text-red-600 border-b-2 border-transparent">{t.logout}</button>
        </div>
      </div>

      {activeTab === 'products' && (
        <div className="space-y-12 animate-in fade-in duration-500">
          <div className="flex justify-end space-x-4">
            <button onClick={openCamera} className="px-6 py-3 border border-black text-[10px] font-bold tracking-widest uppercase flex items-center space-x-2 hover:bg-black hover:text-white transition-all">
              <span>{t.takePhoto}</span>
            </button>
            <button onClick={() => setEditingProduct({ name: { [Language.RU]: '', [Language.UZ]: '' }, description: { [Language.RU]: '', [Language.UZ]: '' }, price: 0, images: [], category: CATEGORIES[0], materialType: 'Teak' as any, dimensions: '', materialDetail: { [Language.RU]: '', [Language.UZ]: '' }, inStock: true })} className="bg-black text-white px-8 py-3 text-[10px] font-bold tracking-widest uppercase">
              +{t.addProduct}
            </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {products.map(p => (
              <div key={p.id} className="bg-white border border-[#E5E5E0] p-6 group hover:border-black transition-colors rounded-sm relative">
                <div className="aspect-square bg-[#F0F0EB] mb-4 overflow-hidden"><img src={p.images[0]} className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500" /></div>
                <h4 className="font-medium text-sm mb-1">{p.name[language]}</h4>
                <div className="flex justify-between items-center mt-4">
                  <span className="text-xs text-gray-400">{p.price.toLocaleString()} {t.currency}</span>
                  <div className="flex space-x-2">
                    <button onClick={() => setEditingProduct(p)} className="p-2 text-gray-400 hover:text-black"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
                    <button onClick={() => setProducts(products.filter(pr => pr.id !== p.id))} className="p-2 text-gray-400 hover:text-red-500"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {editingProduct && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl max-h-[90vh] overflow-y-auto rounded-2xl p-10 animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-light">{editingProduct.id ? t.editProduct : t.addProduct}</h2>
              <button onClick={() => setEditingProduct(null)} className="p-2 text-gray-400 hover:text-black transition-colors"><svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="space-y-6">
                <div>
                  <label className="text-[10px] font-bold uppercase text-gray-400 block mb-1">Название (RU)</label>
                  <input value={editingProduct.name?.[Language.RU] || ''} onChange={e => setEditingProduct(prev => ({...prev, name: {...(prev?.name || { [Language.RU]: '', [Language.UZ]: '' }), [Language.RU]: e.target.value}} as any))} className="w-full bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none" />
