                </div>
                <div>
                  <label className="text-[10px] font-bold uppercase text-gray-400 block mb-1">Описание (RU)</label>
                  <textarea value={editingProduct.description?.[Language.RU] || ''} onChange={e => setEditingProduct(prev => ({...prev, description: {...(prev?.description || { [Language.RU]: '', [Language.UZ]: '' }), [Language.RU]: e.target.value}} as any))} className="w-full bg-[#F9F9F7] p-3 text-sm h-20 border border-[#E5E5E0] rounded-lg outline-none" />
                </div>
                <div>
                  <label className="text-[10px] font-bold uppercase text-gray-400 block mb-1">Описание (UZ)</label>
                  <textarea value={editingProduct.description?.[Language.UZ] || ''} onChange={e => setEditingProduct(prev => ({...prev, description: {...(prev?.description || { [Language.RU]: '', [Language.UZ]: '' }), [Language.UZ]: e.target.value}} as any))} className="w-full bg-[#F9F9F7] p-3 text-sm h-20 border border-[#E5E5E0] rounded-lg outline-none" />
                </div>
              </div>

              <div className="space-y-6">
                <div>
                  <label className="text-[10px] font-bold uppercase text-gray-400 block mb-4">Фото</label>
                  <div className="grid grid-cols-3 gap-2 mb-4">
                    {editingProduct.images?.map((img, idx) => (
                      <div key={idx} className="relative aspect-square rounded overflow-hidden border">
                        <img src={img} className="w-full h-full object-cover" />
                        <button onClick={() => setEditingProduct({...editingProduct, images: editingProduct.images?.filter((_, i) => i !== idx)})} className="absolute top-0 right-0 bg-black/50 text-white p-1"><svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
                      </div>
                    ))}
                    <label className="aspect-square flex flex-col items-center justify-center border-2 border-dashed border-[#E5E5E0] rounded cursor-pointer hover:border-black transition-colors">
                      <span className="text-[8px] uppercase text-gray-400">Добавить</span>
                      <input type="file" multiple accept="image/*" className="hidden" onChange={e => {
                        Array.from(e.target.files || []).forEach(f => {
                          const reader = new FileReader();
                          reader.onload = (ev) => setEditingProduct(prev => ({...prev, images: [...(prev?.images || []), ev.target?.result as string]}) as any);
                          reader.readAsDataURL(f);
                        });
                      }} />
                    </label>
                  </div>
                  <button onClick={openCamera} className="w-full border border-black py-3 text-[10px] font-bold uppercase rounded hover:bg-black hover:text-white transition-all flex items-center justify-center gap-2">
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                    Фото с камеры
                  </button>
                </div>
                <div>
                  <label className="text-[10px] font-bold uppercase text-gray-400 block mb-1">Категория</label>
                  <select value={editingProduct.category} onChange={e => setEditingProduct({...editingProduct, category: e.target.value})} className="w-full bg-transparent border-b border-[#E5E5E0] py-2 text-sm">
                    {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
