                <input placeholder="Telegram Chat ID (числа)" value={newAdmin.chatId} onChange={e => setNewAdmin({...newAdmin, chatId: e.target.value.replace(/[^0-9-]/g, '')})} className="bg-transparent border-b border-[#E5E5E0] py-2 text-sm focus:outline-none" />
                <button onClick={addAdmin} className="bg-black text-white py-2 text-[10px] font-bold uppercase">Добавить</button>
