export enum Language {
  RU = 'ru',
  UZ = 'uz'
}

export enum UserRole {
  SUPER_ADMIN = 'SUPER_ADMIN',
  ADMIN = 'ADMIN',
  USER = 'USER'
}

export interface AdminUser {
  email: string;
  role: UserRole;
  phone?: string;
  telegramChatId?: string;
  name?: string;
}

export interface Category {
  id: string;
  name: { [key in Language]: string };
  cover: string;
}

export type MaterialType = 'Teak' | 'Rattan' | 'Bamboo' | 'Stone' | 'Textile' | string;

export interface Product {
  id: string;
  name: { [key in Language]: string };
  description: { [key in Language]: string };
  price: number;
  images: string[];
  categoryId: string; // Ссылка на ID категории
  materialType: MaterialType;
  dimensions: string;
  materialDetail: { [key in Language]: string };
  inStock: boolean;
}

import React, { useState, useEffect } from 'react';
import { Language, Product, AdminUser, UserRole, Category } from './types';
import { SUPER_ADMIN_EMAIL, INITIAL_PRODUCTS, TRANSLATIONS, ADMIN_TELEGRAM_NUMBER, INITIAL_CATEGORIES } from './constants';
import Navbar from './components/Navbar';
import Catalog from './components/Catalog';
import ProductDetail from './components/ProductDetail';
import AdminPanel from './components/AdminPanel';
import LoginModal from './components/LoginModal';
import ProfileView from './components/ProfileView';

const App: React.FC = () => {
  const [language, setLanguage] = useState<Language>(Language.RU);
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('iboolimi_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });
  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem('iboolimi_categories');
    return saved ? JSON.parse(saved) : INITIAL_CATEGORIES;
  });
  const [admins, setAdmins] = useState<AdminUser[]>(() => {
    const saved = localStorage.getItem('iboolimi_admins');
    return saved ? JSON.parse(saved) : [{ email: SUPER_ADMIN_EMAIL, role: UserRole.SUPER_ADMIN, phone: ADMIN_TELEGRAM_NUMBER }];
  });
  const [currentUser, setCurrentUser] = useState<AdminUser | null>(() => {
    const saved = sessionStorage.getItem('iboolimi_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [view, setView] = useState<{ type: 'catalog' | 'detail' | 'admin' | 'profile', productId?: string }>({ type: 'catalog' });
  const [showLogin, setShowLogin] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    localStorage.setItem('iboolimi_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('iboolimi_categories', JSON.stringify(categories));
  }, [categories]);

  useEffect(() => {
    localStorage.setItem('iboolimi_admins', JSON.stringify(admins));
    if (currentUser) {
      const updated = admins.find(a => a.email === currentUser.email);
      if (updated && JSON.stringify(updated) !== JSON.stringify(currentUser)) {
        setCurrentUser(updated);
        sessionStorage.setItem('iboolimi_session', JSON.stringify(updated));
      }
    }
  }, [admins, currentUser]);

  const handleLogin = (email: string) => {
    const foundAdmin = admins.find(a => a.email.toLowerCase() === email.toLowerCase());
    if (foundAdmin) {
      setCurrentUser(foundAdmin);
      sessionStorage.setItem('iboolimi_session', JSON.stringify(foundAdmin));
    } else {
      const user = { email, role: UserRole.USER };
      setCurrentUser(user);
      sessionStorage.setItem('iboolimi_session', JSON.stringify(user));
    }
    setShowLogin(false);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    sessionStorage.removeItem('iboolimi_session');
    setView({ type: 'catalog' });
  };

  const t = TRANSLATIONS[language];

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        language={language} 
        setLanguage={setLanguage}
        onAdminClick={() => !currentUser ? setShowLogin(true) : currentUser.role === UserRole.USER ? setView({ type: 'profile' }) : setView({ type: 'admin' })}
        onHomeClick={() => setView({ type: 'catalog' })}
        currentUser={currentUser}
        onLogout={handleLogout}
        t={t}
      />

      <main className="flex-grow">
        {view.type === 'catalog' && (
          <Catalog 
            products={products}
            categories={categories}
            language={language} 
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            onProductClick={(id) => setView({ type: 'detail', productId: id })}
            t={t}
          />
        )}

        {view.type === 'detail' && view.productId && (
          <ProductDetail 
            product={products.find(p => p.id === view.productId)!}
            allProducts={products}
            language={language}
            onBack={() => setView({ type: 'catalog' })}
            onProductClick={(id) => setView({ type: 'detail', productId: id })}
            t={t}
          />
        )}

        {view.type === 'admin' && currentUser && (currentUser.role === UserRole.ADMIN || currentUser.role === UserRole.SUPER_ADMIN) && (
          <AdminPanel 
            products={products}
            setProducts={setProducts}
            categories={categories}
            setCategories={setCategories}
            admins={admins}
            setAdmins={setAdmins}
            currentUser={currentUser}
            language={language}
            t={t}
            onLogout={handleLogout}
          />
        )}

        {view.type === 'profile' && currentUser && (
          <ProfileView currentUser={currentUser} language={language} t={t} />
        )}
      </main>

      {showLogin && <LoginModal onLogin={handleLogin} onClose={() => setShowLogin(false)} t={t} />}

      <footer className="bg-gray-900 text-white py-12 px-6 mt-20">
        <div className="max-w-7xl mx-auto text-center md:text-left">
          <h3 className="text-2xl font-light tracking-[0.3em] mb-4">ASIA FURNITURE</h3>
          <p className="text-gray-400 text-sm">© {new Date().getFullYear()} Все права защищены.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Product, Language, Category } from '../types';

interface CatalogProps {
  products: Product[];
  categories: Category[];
  language: Language;
  searchQuery: string;
  setSearchQuery: (q: string) => void;
  onProductClick: (id: string) => void;
  t: any;
}

const Catalog: React.FC<CatalogProps> = ({ products, categories, language, searchQuery, setSearchQuery, onProductClick, t }) => {
  const [selectedCatId, setSelectedCatId] = useState<string | null>(null);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name[language].toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = !selectedCatId || selectedCatId === 'All' || p.categoryId === selectedCatId;
      return matchesSearch && matchesCategory;
    });
  }, [products, searchQuery, selectedCatId, language]);

  if (!selectedCatId && !searchQuery) {
    return (
      <div className="max-w-7xl mx-auto px-6 py-20 animate-in fade-in">
        <div className="mb-24 text-center">
          <h1 className="text-5xl md:text-7xl font-extralight tracking-tighter mb-4">{t.brandName}</h1>
          <p className="text-gray-400 tracking-[0.3em] uppercase text-xs">{t.tagline}</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {categories.map(cat => (
            <div key={cat.id} className="group relative aspect-[4/5] overflow-hidden cursor-pointer bg-[#F0F0EB]" onClick={() => setSelectedCatId(cat.id)}>
              <img src={cat.cover} alt={cat.name[language]} className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110" />
              <div className="absolute inset-0 bg-black/20 group-hover:bg-black/40 transition-colors" />
              <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">
                <h3 className="text-white text-2xl font-light tracking-widest uppercase mb-4">{cat.name[language]}</h3>
                <button className="text-[10px] text-white font-bold tracking-[0.3em] uppercase border-b border-white pb-1 opacity-0 group-hover:opacity-100 transition-opacity">
                  {t.viewCategory}
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  const currentCategory = categories.find(c => c.id === selectedCatId);

  return (
    <div className="max-w-7xl mx-auto px-6 py-12 animate-in fade-in">
      <div className="flex flex-col md:flex-row gap-8 mb-16 items-center justify-between">
        <div className="flex items-center space-x-6">
          <button onClick={() => setSelectedCatId(null)} className="p-3 rounded-full border hover:bg-black hover:text-white transition-all">
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
          </button>
          <h2 className="text-3xl font-light tracking-tight">{currentCategory ? currentCategory.name[language] : t.all}</h2>
        </div>
        <input type="text" placeholder={t.search} value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full md:w-64 bg-transparent border-b py-2 text-sm outline-none focus:border-black" />
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-12">
        {filteredProducts.map(product => (
          <div key={product.id} className="group cursor-pointer" onClick={() => onProductClick(product.id)}>
            <div className="aspect-[3/4] overflow-hidden bg-[#F0F0EB] mb-4">
              <img src={product.images[0]} className="w-full h-full object-cover grayscale-[0.3] group-hover:grayscale-0 transition-all duration-700" />
            </div>
            <div className="flex justify-between items-start">
              <h3 className="text-lg font-light">{product.name[language]}</h3>
              <div className="text-sm font-medium">{product.price.toLocaleString()} {t.currency}</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Catalog;

import React, { useState, useRef } from 'react';
import { Product, AdminUser, UserRole, Language, Category } from '../types';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  categories: Category[];
  setCategories: React.Dispatch<React.SetStateAction<Category[]>>;
  admins: AdminUser[];
  setAdmins: React.Dispatch<React.SetStateAction<AdminUser[]>>;
  currentUser: AdminUser;
  language: Language;
  t: any;
  onLogout: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  products, setProducts, categories, setCategories, admins, setAdmins, currentUser, language, t, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'categories' | 'team' | 'settings' | 'my-profile'>('products');
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);
  const [editingCategory, setEditingCategory] = useState<Partial<Category> | null>(null);
  const [newAdmin, setNewAdmin] = useState({ email: '', phone: '', chatId: '' });
  const [botToken, setBotToken] = useState(localStorage.getItem('iboolimi_bot_token') || '');
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const isSuperAdmin = currentUser.role === UserRole.SUPER_ADMIN;

  const handleSaveProduct = () => {
    const p = editingProduct;
    if (!p?.name?.[Language.RU] || !p?.price || !p?.categoryId) {
      alert("Заполните Название (RU), Цену и выберите Раздел");
      return;
    }

    const finalProduct = {
      id: p.id || Date.now().toString(),
      name: p.name || { [Language.RU]: '', [Language.UZ]: '' },
      description: p.description || { [Language.RU]: '', [Language.UZ]: '' },
      price: p.price || 0,
      images: p.images || [],
      categoryId: p.categoryId,
      materialType: p.materialType || '',
      dimensions: p.dimensions || '',
      materialDetail: p.materialDetail || { [Language.RU]: '', [Language.UZ]: '' },
      inStock: p.inStock !== undefined ? p.inStock : true
    } as Product;

    if (p.id) {
      setProducts(products.map(item => item.id === p.id ? finalProduct : item));
    } else {
      setProducts([finalProduct, ...products]);
    }
    setEditingProduct(null);
  };

  const handleSaveCategory = () => {
    const c = editingCategory;
    if (!c?.name?.[Language.RU] || !c?.cover) {
      alert("Укажите название (RU) и обложку");
      return;
    }

    const finalCat = {
      id: c.id || `cat-${Date.now()}`,
      name: c.name || { [Language.RU]: '', [Language.UZ]: '' },
      cover: c.cover || ''
    } as Category;

    if (c.id) {
      setCategories(categories.map(item => item.id === c.id ? finalCat : item));
    } else {
      setCategories([...categories, finalCat]);
    }
    setEditingCategory(null);
  };

  const openCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      streamRef.current = stream;
      setIsCameraOpen(true);
      setTimeout(() => { if (videoRef.current) videoRef.current.srcObject = stream; }, 100);
    } catch (err) { alert("Камера недоступна"); }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const canvas = canvasRef.current;
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
      const data = canvas.toDataURL('image/jpeg');
      if (editingProduct) {
        setEditingProduct(prev => ({ ...prev, images: [...(prev?.images || []), data] }));
      } else if (editingCategory) {
        setEditingCategory(prev => ({ ...prev, cover: data }));
      }
      closeCamera();
    }
  };

  const closeCamera = () => {
    streamRef.current?.getTracks().forEach(t => t.stop());
    setIsCameraOpen(false);
  };

  return (
